import type { Drill } from "./types";

// Agriculture / mid drills, keyed by module slug — 25 per module.
// Farm manager / skipper / crew lead: runs crews through planting and harvest, coordinates
// suppliers, buyers, vets and agronomists, and answers to the owner or co-op board. Merged into course.ts.
export const AGRICULTURE_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-agri-mid-01","level":"mid","profession":"agriculture","title":"The rain-window text","scenario":"The forecast just changed: three dry days starting tomorrow, then a week of rain. You've decided to start combining wheat at dawn instead of Thursday. Your draft text to the owner opens with a recap of the whole forecast discussion.","task":"Write a 1-2 sentence text that leads with the decision.","tips":["First words: what you're doing and when.","The forecast is the reason — it comes second.","The owner needs the plan, not the weather narration."],"focus":["clarity","structure"],"placeholder":"We start combining at dawn tomorrow —"},
    {"id":"lead-agri-mid-02","level":"mid","profession":"agriculture","title":"The baler is down","scenario":"The baler broke a pickup band with 80 acres of hay cut and rain coming Saturday. You're calling the dealer's parts desk. You tend to start with the story of how it broke.","task":"Write the first two sentences of the call, leading with the part and the deadline.","tips":["Open with the part number or part name and when you need it.","'Rain Saturday' is the deadline — say it in sentence one or two.","How it broke only matters if they ask."],"focus":["clarity","impact"],"placeholder":"I need a pickup band for a 605N baler in hand by Friday —"},
    {"id":"lead-agri-mid-03","level":"mid","profession":"agriculture","title":"The morning huddle that wanders","scenario":"Eight crew members are standing at the shop at 6:30 a.m. waiting for assignments. You have a habit of opening with the weather, then yesterday's progress, before anyone learns where they're going.","task":"Write the first two sentences of the huddle that put today's assignments first.","tips":["First sentence: who goes where.","People can't start moving until they hear their name and field.","Weather and context come after, and only if they change the plan."],"focus":["structure","concision"]},
    {"id":"lead-agri-mid-04","level":"mid","profession":"agriculture","title":"The vet voicemail","scenario":"A heifer is off feed, drooling, and two more in the same pen look dull. If it's contagious you need the vet today, not Thursday. Your voicemails usually open with pleasantries and end with the ask.","task":"Write a 3-sentence voicemail that leads with what you need and why it's urgent.","tips":["First sentence: 'I need a visit today' plus the one-line reason.","Symptoms are support — keep them to a sentence.","End with your callback number and where you'll be."],"focus":["clarity","impact"],"placeholder":"I need you out today if possible — I may have something contagious in the heifer pen."},
    {"id":"lead-agri-mid-05","level":"mid","profession":"agriculture","title":"The yield question","scenario":"The owner texts from vacation: 'How's the corn looking?' You've walked the fields and your honest estimate is 190-200 bushels an acre, a little above last year. Your instinct is to describe each field before giving a number.","task":"Write a 1-2 sentence reply that gives the number first.","tips":["Lead with the estimate and the comparison to last year.","Field-by-field detail is for later or on request.","A range is fine — vagueness is not."],"focus":["precision","concision"],"placeholder":"Looking like 190-200 bu/ac — a touch better than last year."},
    {"id":"lead-agri-mid-06","level":"mid","profession":"agriculture","title":"The short-load email","scenario":"Blossom drop means you can only fill 70% of the wholesale buyer's tomato order for the next two weeks. You have to email their purchasing manager. Your draft spends a paragraph on the heat wave before mentioning the shortfall.","task":"Write a 2-3 sentence email that states the shortfall and revised volume up front.","tips":["Sentence one: the revised volume and the dates it covers.","One sentence of cause is plenty.","Close with what you can commit to and when you'll update them."],"focus":["clarity","structure"],"placeholder":"We'll be at about 70% of contracted volume for the next two weeks —"},
    {"id":"lead-agri-mid-07","level":"mid","profession":"agriculture","title":"The board update headline","scenario":"You're giving the monthly update to the co-op board. The real news: harvest finished four days early and yields came in 8% over plan. You usually start with a chronological walk through the month.","task":"Write the opening two sentences of the update, headline first.","tips":["Lead with the result the board cares about most.","Numbers in sentence one, story after.","Chronology is for the appendix, not the opening."],"focus":["structure","impact"],"placeholder":"Harvest is done — four days early, and yields came in 8% over plan."},
    {"id":"lead-agri-mid-08","level":"mid","profession":"agriculture","title":"The pivot down in a heat wave","scenario":"Pivot 6 stopped mid-circle and it's forecast to hit 38°C for three days. The corn under it can't wait. You're radioing your irrigation tech, who is fixing a leak on the far side of the farm.","task":"Write a 1-2 sentence radio message that leads with the new priority.","tips":["First words: drop what you're doing, pivot 6 first.","Say why in half a sentence — the heat.","Keep radio messages to what changes their next hour."],"focus":["clarity","concision"],"placeholder":"Leave the leak — pivot 6 is down and I need it running today."},
    {"id":"lead-agri-mid-09","level":"mid","profession":"agriculture","title":"The seed decision deadline","scenario":"The seed dealer's early-order discount ends Friday, worth about $4,000 on your volume. The owner still hasn't picked between the two soybean varieties you shortlisted. Your draft message re-explains both varieties from scratch.","task":"Write a 2-sentence message that leads with the decision needed and the deadline.","tips":["Sentence one: 'I need your pick by Thursday' plus what it's worth.","Offer your recommendation so a busy owner can just say yes.","The variety comparison already exists — link or reference it, don't repeat it."],"focus":["clarity","impact"],"placeholder":"Need your call on soybean variety by Thursday — the early-order discount ($4k) ends Friday."},
    {"id":"lead-agri-mid-10","level":"mid","profession":"agriculture","title":"The incident status message","scenario":"A crew member cut his hand on the packing line this morning. He was treated at the clinic, got three stitches, and is back on light duty. You need to tell the owner, and your draft opens with a long description of how it happened.","task":"Write a 2-3 sentence message that leads with the outcome: treated and back at work.","tips":["First sentence: he's okay — that's what the owner needs first.","Then the one-line facts: what happened, where.","End with what you've changed so it doesn't repeat."],"focus":["clarity","structure"],"placeholder":"Marco cut his hand on the packing line this morning — three stitches, he's fine and back on light duty."},
    {"id":"lead-agri-mid-11","level":"mid","profession":"agriculture","title":"The labor contractor call","scenario":"Picking is running ahead of the crew you have. You need six more pickers from the labor contractor starting Monday, for about three weeks. On calls like this you tend to open with small talk and circle to the ask.","task":"Write the first two sentences of the call, ask first.","tips":["Lead with the number, the start date, and the duration.","Small talk can follow the ask, not replace it.","Give him what he needs to say yes: crop, piece rate, housing status."],"focus":["clarity","precision"]},
    {"id":"lead-agri-mid-12","level":"mid","profession":"agriculture","title":"The fuel order","scenario":"Harvest starts in ten days and the diesel tank is at a quarter. You're emailing the fuel supplier to schedule two deliveries around your harvest window. Your draft opens with how busy the season has been.","task":"Write a 2-sentence email that leads with the order: volumes and dates.","tips":["Sentence one: what you need delivered and when.","Two deliveries means two dates — name both.","Ask for confirmation so you're not chasing it later."],"focus":["clarity","concision"]},
    {"id":"lead-agri-mid-13","level":"mid","profession":"agriculture","title":"The skipper's call ashore","scenario":"You're skippering the boat and the hold is full two days early. You're radioing the fleet manager so the offload crew and buyer are ready when you land. You tend to start with how the trip went.","task":"Write a 1-2 sentence radio call that leads with your ETA and what you're carrying.","tips":["First words: ETA and approximate tonnage.","The shore side plans around those two numbers — give them first.","Trip stories keep for the dock."],"focus":["clarity","precision"],"placeholder":"Hold's full — we'll be at the dock 0600 Thursday with about 40 tonnes."},
    {"id":"lead-agri-mid-14","level":"mid","profession":"agriculture","title":"The frost-night text","scenario":"A radiation frost is forecast for 2 a.m. and the apricots are at full bloom. You're texting the two crew members on frost duty tonight. Your draft explains inversion layers before getting to instructions.","task":"Write a 2-sentence text that leads with the instruction: who starts what, at what time or temperature.","tips":["Instruction first: start the wind machines at 0°C or 2 a.m., whichever comes first.","Name who covers which block.","Science is optional; the trigger point is not."],"focus":["clarity","precision"],"placeholder":"Frost duty tonight: start the wind machines when the low block hits 0°C —"},
    {"id":"lead-agri-mid-15","level":"mid","profession":"agriculture","title":"The moisture call","scenario":"The wheat is testing 16.5% moisture and the elevator docks hard above 14.5%. Your recommendation: wait three days. The owner wants to start now. Your draft message buries the recommendation under all the moisture readings.","task":"Write a 2-3 sentence message that leads with the recommendation, then the key number.","tips":["Sentence one: wait until Thursday, and what waiting saves.","One number carries the argument — 16.5% against a 14.5% dock line.","Acknowledge the itch to start; give the cost of scratching it."],"focus":["clarity","impact"],"placeholder":"I'd hold off until Thursday — we're testing 16.5% and the dock above 14.5% would cost us real money."},
    {"id":"lead-agri-mid-16","level":"mid","profession":"agriculture","title":"Custom harvester or repair","scenario":"The combine needs a $22,000 repair mid-season. You've priced a custom harvester who can cover the remaining acres for $18,000. You have a clear pick — hire the custom crew, repair in the off-season — but your draft to the owner reads like a neutral comparison.","task":"Rewrite the opening so your recommendation comes first, with the two numbers behind it.","tips":["State your pick in sentence one.","Two numbers, side by side, make the case fast.","A neutral menu forces the owner to do your job."],"focus":["structure","clarity"],"placeholder":"I'd hire the custom crew and push the repair to the off-season —"},
    {"id":"lead-agri-mid-17","level":"mid","profession":"agriculture","title":"The tire approval","scenario":"The planter tractor needs four tires before spring — about $6,800 — and the shop needs two weeks' lead time. Planting starts in five weeks. Your draft to the owner spends three sentences on how worn the tires are before asking for the money.","task":"Write a 2-sentence approval request that leads with the ask and the deadline.","tips":["Sentence one: the amount and when you need the yes.","Tie the deadline to planting so it's not just a shop preference.","Wear detail is one clause, not a paragraph."],"focus":["clarity","impact"]},
    {"id":"lead-agri-mid-18","level":"mid","profession":"agriculture","title":"The hay inquiry callback","scenario":"A horse-farm owner left a voicemail asking how much hay you have and your price. You have 400 small squares of second-cut at $9 a bale. Returning the call, you tend to talk about the growing season before quoting.","task":"Write the first two sentences of your callback, answer first.","tips":["Lead with the two things she asked: quantity and price.","Quality note — second cut, barn stored — earns one clause.","Then the logistics question: pickup or delivery?"],"focus":["concision","clarity"],"placeholder":"I've got 400 small squares of second-cut at $9 a bale, barn stored."},
    {"id":"lead-agri-mid-19","level":"mid","profession":"agriculture","title":"The Friday report opener","scenario":"Your weekly email to the owner covers a lot: planting 60% done and ahead of schedule, a hydraulic leak fixed, one hire made. You usually open with the weather and work through the week day by day.","task":"Write the opening sentence of the report, leading with the headline that matters most.","tips":["One sentence that says how the week nets out: ahead, behind, or on plan.","Pick the single number the owner would repeat to someone else.","Day-by-day is what bullets are for."],"focus":["structure","concision"],"placeholder":"Planting is 60% done — two days ahead of schedule."},
    {"id":"lead-agri-mid-20","level":"mid","profession":"agriculture","title":"The aphid decision","scenario":"The agronomist's scouting report found aphids at threshold in the canola. Spraying works if it happens within about 48 hours; the sprayer needs booking today. Your message to the owner starts by summarizing the whole scouting report.","task":"Write a 2-sentence message that leads with the decision and the clock.","tips":["Sentence one: I need a yes on spraying by tonight.","Give the cost and the cost of waiting — two numbers.","The full report can ride along as an attachment."],"focus":["clarity","impact"],"placeholder":"Aphids hit threshold in the canola — I need a go/no-go on spraying by tonight."},
    {"id":"lead-agri-mid-21","level":"mid","profession":"agriculture","title":"The milk-quality alert","scenario":"The bulk tank somatic cell count has climbed three tests in a row and is nearing the processor's penalty line. You've already pulled two suspect cows and called the vet. Your text to the owner starts with an explanation of what cell counts are.","task":"Write a 2-3 sentence text that leads with the situation and what you've already done.","tips":["Sentence one: the count is climbing and how close to the penalty line.","Sentence two: actions already taken — that's what calms an owner.","The owner knows what SCC is; skip the lecture."],"focus":["clarity","structure"]},
    {"id":"lead-agri-mid-22","level":"mid","profession":"agriculture","title":"The flooded forty","scenario":"The low forty acres flooded again and replanting would cost about $3,200 in seed with maybe six weeks of season left. Your call: leave it and claim prevented planting where you can. Your draft walks the owner through the whole drainage history first.","task":"Write a 2-sentence message that leads with the recommendation.","tips":["Recommendation first: leave the low forty this year.","One line of arithmetic: replant cost against the odds.","Drainage history is a winter conversation, not this message."],"focus":["clarity","structure"],"placeholder":"I'd leave the low forty — replanting is $3,200 in seed against long odds this late."},
    {"id":"lead-agri-mid-23","level":"mid","profession":"agriculture","title":"Borrowing the grain cart","scenario":"Your grain cart's axle cracked and the shop can't get to it for a week. Your neighbor's cart sits idle until his corn is ready, about ten days out. You're texting to ask, and your draft is mostly apology and backstory.","task":"Write a 2-sentence text that leads with the ask and the return date.","tips":["Ask first: can I borrow the cart through next Friday?","Say when he gets it back — that's the question he'll have.","Offer something concrete in return; skip the apologizing."],"focus":["clarity","concision"]},
    {"id":"lead-agri-mid-24","level":"mid","profession":"agriculture","title":"The mechanic's triage message","scenario":"The swather is throwing a hydraulic fault code and you have 120 acres to cut before Sunday's rain. You're messaging your mobile mechanic, who triages jobs by urgency. Your draft describes everything you observed in the order you noticed it.","task":"Write a 2-3 sentence message that leads with the machine, the symptom, and the deadline.","tips":["First sentence: which machine, what it's doing, when you need it running.","Fault code and observations go second — they help him bring parts.","Tell him where the machine is parked."],"focus":["clarity","precision"],"placeholder":"Swather's down with a hydraulic fault and I need it cutting by Friday —"},
    {"id":"lead-agri-mid-25","level":"mid","profession":"agriculture","title":"The hail claim call","scenario":"Last night's hail hit about 300 acres of soybeans, damage ranging from shredded to bruised. You're calling the crop insurance adjuster's office to start the claim. Your instinct is to describe the storm before stating what you need.","task":"Write the first two sentences of the call, leading with the claim and the inspection ask.","tips":["Sentence one: policy holder, crop, acres affected — the claim in one line.","Sentence two: the ask — an inspection date this week.","Storm drama doesn't move a claim; acreage and dates do."],"focus":["clarity","precision"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-agri-mid-01","level":"mid","profession":"agriculture","title":"Translate the agronomist","scenario":"The agronomist's report says the corn shows 'interveinal chlorosis consistent with sulfur deficiency, recommend 15 lb/ac ammonium sulfate at V6.' The owner is sharp on money and logistics but doesn't speak agronomy. You're forwarding the recommendation.","task":"Write a 2-3 sentence note that translates the report into cost, timing, and payoff for the owner.","tips":["Lead with what it means: the corn is short of sulfur and fixable.","Convert the recommendation to dollars per acre and a spray date.","Keep the Latin in the attachment."],"focus":["audience","clarity"],"placeholder":"The corn is running short of sulfur — fixable for about $12/ac if we apply in the next two weeks."},
    {"id":"audience-agri-mid-02","level":"mid","profession":"agriculture","title":"The chef wants lettuce","scenario":"Cool nights have slowed the lettuce and the restaurant buyer's order will land five days late. Your draft explains growing-degree days and soil temperature. The chef cares about one thing: what to put on next week's menu.","task":"Write a 2-3 sentence message in the chef's terms: dates, what's available instead, and when full supply resumes.","tips":["Answer her real question: what can I count on, and when?","Offer the substitute you can deliver on time.","Growing-degree days mean nothing on a menu."],"focus":["audience","clarity"],"placeholder":"Lettuce will be 5 days behind — landing Tuesday the 14th instead of Thursday."},
    {"id":"audience-agri-mid-03","level":"mid","profession":"agriculture","title":"The first-day safety talk","scenario":"Twelve seasonal workers start tomorrow. Several are brand new to farm work and a few have limited English. Your safety briefing draft is written like the insurance company's manual: 'employees must maintain situational awareness around powered equipment.'","task":"Rewrite three rules of the briefing in plain, physical language a first-day worker will remember.","tips":["Say what to do with their body: 'never walk behind a machine that's running.'","One rule per sentence, short words.","Test each line: could someone repeat it back at lunch?"],"focus":["audience","clarity"],"placeholder":"Rule one: if a machine is running, the driver must see you before you go near it."},
    {"id":"audience-agri-mid-04","level":"mid","profession":"agriculture","title":"The board of two worlds","scenario":"The co-op board is four retired farmers and an accountant. You're presenting the case for upgrading the shared grain dryer. Your draft is all throughput specs for the farmers, with nothing for the accountant — who asks the deciding questions.","task":"Write a 2-3 sentence summary that lands with both: capacity in plain terms, payback in numbers.","tips":["Give the farmers the practical gain: hours saved per thousand bushels.","Give the accountant the payback period and financing cost.","One primary message both groups can vote on."],"focus":["audience","structure"]},
    {"id":"audience-agri-mid-05","level":"mid","profession":"agriculture","title":"The mechanic's diagnosis, the owner's decision","scenario":"The mechanic says the tractor needs 'injectors, a high-pressure pump, and probably a turbo before fall — call it $14K, or she'll leave you standing in the field.' The owner needs a decision framed in downtime and dollars, not parts.","task":"Write a 2-3 sentence message translating the diagnosis into the owner's terms: cost, risk, and timing.","tips":["Lead with the decision: fix now for $14K or risk losing it mid-harvest.","Downtime during harvest is the real cost — name it.","The parts list is evidence, not the message."],"focus":["audience","impact"],"placeholder":"The 8320 needs $14K of fuel-system work — do it now, or risk it dying mid-harvest when every day costs us."},
    {"id":"audience-agri-mid-06","level":"mid","profession":"agriculture","title":"Re-entry interval, crew version","scenario":"You sprayed block C last night and the label says a 24-hour restricted-entry interval. The picking crew's version of this needs to be about their day, not the label language: where they can work, when block C opens, and why it matters for them.","task":"Write a 2-sentence morning announcement in the crew's terms.","tips":["Lead with what changes for them: pick block D today, C opens tomorrow at 7.","Give the reason in one plain clause — spray needs a day to settle.","Label citations belong in the spray log, not the huddle."],"focus":["audience","clarity"],"placeholder":"Stay out of block C today — we sprayed last night and it opens tomorrow at 7."},
    {"id":"audience-agri-mid-07","level":"mid","profession":"agriculture","title":"Why the logbook matters","scenario":"Your crew leads treat the organic-certification field logs as pointless paperwork, and entries are getting sloppy. The inspector visit is in six weeks. You need them to understand the stake in their terms: one bad log can cost the premium on the whole crop.","task":"Write a 3-4 sentence explanation of why the logs matter, framed around consequences the crew leads care about.","tips":["Translate 'compliance' into money and jobs: the organic premium pays the winter payroll.","Make the failure concrete: one missing spray entry can void the field's certification.","End with the specific habit you want: log it the same day, every time."],"focus":["audience","impact"]},
    {"id":"audience-agri-mid-08","level":"mid","profession":"agriculture","title":"The vet's instructions, parlor version","scenario":"The vet diagnosed a mastitis flare and left instructions full of dosing schedules and withholding periods. The milking crew needs to know exactly what to do differently at 5 a.m.: which cows, what marking, which milk gets dumped.","task":"Write a 3-sentence note for the parlor wall in the crew's operational terms.","tips":["Name the cows and the visible marker — red leg band, not ear-tag numbers they'd have to look up.","Say what happens to the milk in plain words: bucket, dump, never the tank.","Dosing is your job or the herdsman's — don't crowd the note with it."],"focus":["audience","clarity","precision"],"placeholder":"The three cows with red leg bands get milked last, into the bucket — that milk is dumped, never the tank."},
    {"id":"audience-agri-mid-09","level":"mid","profession":"agriculture","title":"The investor-owner check-in","scenario":"The farm's new owner is a city investor who visits twice a year. She asked, 'How's the season going?' Your instinct is to talk tillering, test weights, and basis. She's really asking: is my investment on track, and is anything wrong?","task":"Write a 3-4 sentence answer with zero jargon that addresses her actual question.","tips":["Answer the underlying question first: on track, ahead, or behind — against budget.","Pick one plain-language proof point, not five technical ones.","Flag the one risk you're watching, with what you're doing about it."],"focus":["audience","clarity"],"placeholder":"We're on track — slightly ahead of budget, and the crop looks average or better everywhere."},
    {"id":"audience-agri-mid-10","level":"mid","profession":"agriculture","title":"The lender paragraph","scenario":"The owner asked you to draft the operations paragraph for the bank's annual review. The loan officer cares about cash flow and risk management, not machinery or varieties. Your first draft reads like a newsletter about the farm's busy year.","task":"Write a 3-4 sentence paragraph aimed at what a lender reads for.","tips":["Lead with production against plan — the thing that repays the loan.","Show risk handled: insurance in place, forward sales locked, costs controlled.","Cut anything the lender can't use to assess repayment."],"focus":["audience","precision"]},
    {"id":"audience-agri-mid-11","level":"mid","profession":"agriculture","title":"The market-stand sign","scenario":"The drought made this year's strawberries small, though flavor is exceptional. Market customers keep asking, and your staff shrug. You're writing a small sign for the stand — for shoppers, not for farmers.","task":"Write a 1-2 sentence sign that turns the question into a selling point.","tips":["Customers care about taste and value, not rainfall data.","Lead with the benefit: small and sweet.","Keep it warm and short — it's a sign, not a report."],"focus":["audience","concision"],"placeholder":"Small berries, big flavor — the dry summer concentrated the sugar."},
    {"id":"audience-agri-mid-12","level":"mid","profession":"agriculture","title":"Selling GPS to a veteran operator","scenario":"Your best operator, 30 years on tractors, refuses to trust the new auto-steer. Your pitch so far has been about sub-inch accuracy and section control — features. His stake is different: less fatigue on 14-hour days and no overlap ribbing from the younger guys.","task":"Write what you'd say to him in 2-3 sentences, framed entirely around his stake.","tips":["Drop the spec sheet; talk about his shoulders at hour twelve.","Respect the skill: the system holds the line so his judgment goes where it matters.","Invite a trial on his terms, not a mandate."],"focus":["audience","impact"]},
    {"id":"audience-agri-mid-13","level":"mid","profession":"agriculture","title":"The first-day info sheet","scenario":"Your seasonal-hire welcome sheet is two pages of policy language. What a new picker actually needs on day one: where to park, what time and where to show up, what to bring, who their lead is, and when they get paid.","task":"Write the five lines that should be at the top of the sheet.","tips":["Order by their morning: parking, start time, meeting point.","Name a person, not a department: 'Your lead is Rosa.'","Payday is the question they won't ask — answer it anyway."],"focus":["audience","clarity","concision"]},
    {"id":"audience-agri-mid-14","level":"mid","profession":"agriculture","title":"One message, one audience","scenario":"The irrigation district just cut your water allocation 20%. You start drafting one message to send to both the owner and the crew — and it serves neither: the owner needs financial impact and options, the crew needs schedule changes.","task":"Pick ONE audience and write the 2-3 sentence version for them alone.","tips":["Decide who must act first — that's your primary audience.","The owner's version is dollars and decisions; the crew's is shifts and fields.","A message for everyone lands with no one."],"focus":["audience","structure"]},
    {"id":"audience-agri-mid-15","level":"mid","profession":"agriculture","title":"The quota cut, deck version","scenario":"You're the skipper and the fishery just cut this season's quota 15%. The owner has heard it in management terms. Your deckhands need it in their terms: trips, hours, and what it does to their share this season.","task":"Write a 3-sentence version for the crew that answers what they'll actually ask.","tips":["Lead with what changes for them: likely two fewer trips, shares down roughly in line.","Be straight about what you don't control.","Say what you'll do to protect their season — target the higher-value grounds."],"focus":["audience","clarity"],"placeholder":"The quota cut means probably two fewer trips this season, so shares will be down —"},
    {"id":"audience-agri-mid-16","level":"mid","profession":"agriculture","title":"NDVI map to sprinkler schedule","scenario":"The agronomist sent drone NDVI maps showing stress in the northeast zones of two pivots. Your irrigation tech doesn't read vegetation indices — he reads zones, hours, and valve numbers. You're passing along what to change.","task":"Write a 2-sentence instruction that converts the map into his operating terms.","tips":["Translate colors to actions: which zones, how many extra hours.","Name the equipment the way he does — pivot 3 northeast span, not 'the stressed polygon.'","Attach the map for reference; don't make it the message."],"focus":["audience","clarity","precision"]},
    {"id":"audience-agri-mid-17","level":"mid","profession":"agriculture","title":"What the elevator dispatcher needs","scenario":"You're setting up harvest deliveries with the grain elevator's dispatcher. Your draft describes your harvest plan — field order, combine logistics, crew shifts. She schedules dump pits; she needs trucks per day, hours, commodity, and rough moisture.","task":"Rewrite the message to give the dispatcher only what she schedules by.","tips":["Her four facts: commodity, loads per day, delivery hours, moisture range.","Your field logistics are your business — cut them.","Ask her constraint in return: any pit hours or days to avoid?"],"focus":["audience","concision","precision"],"placeholder":"Starting Monday: wheat, about 8 loads a day between 9 and 6, testing 13.5-14.5."},
    {"id":"audience-agri-mid-18","level":"mid","profession":"agriculture","title":"The school-tour opener","scenario":"A fourth-grade class is visiting the dairy on Friday. Your usual farm-tour opening — herd size, rolling herd average, robotic milkers — is calibrated for other farmers. Nine-year-olds need one vivid idea to hang the day on.","task":"Write a 2-3 sentence opening for the kids.","tips":["Pick one concrete, astonishing fact a kid can retell at dinner.","Anchor everything to their world: cereal, cheese, the milk in their fridge.","Questions beat facts: open with one you'll answer during the tour."],"focus":["audience","impact"]},
    {"id":"audience-agri-mid-19","level":"mid","profession":"agriculture","title":"The phone-screen report","scenario":"The owner reads your reports on his phone between meetings and has told you he rarely gets past the first paragraph. Your weekly update is 400 words. This week: spraying done, one breakdown fixed, corn looking strong, one decision needed on hay marketing.","task":"Write the whole report as 3 sentences a phone reader finishes.","tips":["Sentence one: state of play. Sentence two: what happened. Sentence three: the decision you need.","If he reads only sentence one, he should still be safe.","Everything else waits for the monthly review."],"focus":["audience","concision","structure"]},
    {"id":"audience-agri-mid-20","level":"mid","profession":"agriculture","title":"The night-shift changeover","scenario":"The new milking routine — pre-dip change and a longer wait time — starts Monday. You briefed the day shift in person, but the night shift only gets a written note. They weren't in the meeting and don't know the background.","task":"Write a 3-sentence note for the night shift that assumes they know nothing about the change.","tips":["Beat the curse of knowledge: they didn't hear the vet's explanation — give the one-line why.","Describe the new routine as steps, in order.","Name who to call at 2 a.m. with questions."],"focus":["audience","clarity"],"placeholder":"Starting Monday night we're changing the pre-dip routine — new dip, and 30 seconds contact time before wiping."},
    {"id":"audience-agri-mid-21","level":"mid","profession":"agriculture","title":"Cover crops for a cost-cutter","scenario":"The owner's first question about any proposal is 'what does it cost me?' You want to plant cover crops on 200 acres. Your draft leads with soil biology and organic matter — his eyes will glaze by sentence two.","task":"Write a 2-3 sentence pitch that opens inside his frame: cost, payback, risk.","tips":["Lead with the number he'll ask for: $38/ac, and where it comes back.","Translate soil health into his terms: less fertilizer bought, fewer washouts to fix.","One benefit argued well beats five listed."],"focus":["audience","impact"],"placeholder":"Cover crops on the 200 acres cost about $38/ac — and I expect most of that back in fertilizer savings within two seasons."},
    {"id":"audience-agri-mid-22","level":"mid","profession":"agriculture","title":"Contract spec to sorting table","scenario":"The new buyer contract specifies 'US No. 1, minimum 2.5-inch diameter, max 5% defects by count.' The packing-shed lead runs a sorting line, not a contracts desk. She needs the spec as physical sorting instructions her table crew can apply at speed.","task":"Write a 2-3 sentence instruction that converts the spec into what the sorters see and do.","tips":["Turn the diameter into the tool: anything that fits through the small ring gets culled.","Turn '5% defects' into a line-speed rule: when in doubt, pull it.","Post the three most common defects as pictures, not words."],"focus":["audience","clarity","precision"]},
    {"id":"audience-agri-mid-23","level":"mid","profession":"agriculture","title":"Housing rules, plainly","scenario":"The H-2A housing inspection is next month and some rules directly affect your workers — occupancy limits, no cooking in sleeping rooms, reporting broken fixtures. The official notice is dense legal English; half your crew reads English as a second language.","task":"Write 3 short rules for the housing notice board in the plainest language you can.","tips":["One rule per line, under ten words each.","Frame positively where you can: 'Report broken things to Rosa — same day.'","If it needs a second read, it's too long."],"focus":["audience","clarity","concision"]},
    {"id":"audience-agri-mid-24","level":"mid","profession":"agriculture","title":"Drone results for the crew chief","scenario":"You flew the drone over the potatoes and found two wet spots and a section of poor emergence. The crew chief plans tomorrow's scouting and repair work. He needs locations and tasks, not imagery talk.","task":"Write a 2-sentence tasking note in the crew chief's terms.","tips":["Give locations the way he navigates: row numbers and landmarks, not coordinates.","Attach one annotated photo — a circle beats a paragraph.","Say the task, not the finding: 'walk rows 40-55 and check the drain.'"],"focus":["audience","clarity"]},
    {"id":"audience-agri-mid-25","level":"mid","profession":"agriculture","title":"The note to the organic neighbor","scenario":"You're spraying the east field Thursday if wind allows. Your neighbor's certified-organic vegetables border it, and drift onto his crop could cost him his certification. You're giving him a heads-up; what he cares about is his boundary, your product, and the wind rule you'll follow.","task":"Write a 2-3 sentence message framed around his stake, not your schedule.","tips":["Lead with what protects him: the buffer you'll leave and your wind cutoff.","Name the product and the day, so he can plan his own harvest.","Invite the call: 'if Thursday is bad for you, tell me.'"],"focus":["audience","clarity","impact"],"placeholder":"I'm planning to spray the east field Thursday — I'll leave a 30-metre buffer on your boundary and won't spray above 12 km/h wind."}
  ],
  "structure-that-carries": [
    {"id":"structure-agri-mid-01","level":"mid","profession":"agriculture","title":"Twelve tasks, three buckets","scenario":"Your pre-planting list is a jumble: calibrate the planter, order inoculant, fix the seed tender auger, walk fields for washouts, service the drill, book the fertilizer spreader, hire two operators, test soil in the north quarter, and more. The crew meeting is tomorrow and the list as written will glaze eyes.","task":"Group the work into 3 named buckets and write the one-line heading for each.","tips":["Group by how the work gets done: equipment, field prep, people and inputs.","Each heading should tell a crew lead what's inside without reading the items.","If a task fits two buckets, pick where its owner lives."],"focus":["structure","clarity"]},
    {"id":"structure-agri-mid-02","level":"mid","profession":"agriculture","title":"SCQA for the second truck","scenario":"You want the board to approve a second grain truck. The raw facts: hauling delays cost combine hours every harvest, the custom trucker raised rates 30%, a good used truck is $85,000. You need a two-minute framing that makes the decision feel inevitable.","task":"Write the Situation, Complication, Question, and Answer as one sentence each.","tips":["Situation: what everyone already agrees on — we haul everything with one truck.","Complication: what changed — custom rates up 30% and the combine now waits.","The Answer is your recommendation, not a menu."],"focus":["structure","impact"],"placeholder":"Situation: we move the whole harvest with one truck and hired hauling."},
    {"id":"structure-agri-mid-03","level":"mid","profession":"agriculture","title":"PREP on the fertilizer overrun","scenario":"At the review meeting the owner asks, point blank: 'Why did we go over on fertilizer?' You know the answer — prices rose 18% after budgeting, and you added 60 rented acres — but under the question you tend to ramble through the whole season.","task":"Give a spoken PREP answer: Point, Reason, Example, Point — 4 sentences.","tips":["Point first: 'We went over for two reasons, price and acres — not waste.'","One number per reason is enough.","Restate the point at the end so it's what he remembers."],"focus":["structure","clarity"],"placeholder":"We went over for two reasons — price and added acres, not overuse."},
    {"id":"structure-agri-mid-04","level":"mid","profession":"agriculture","title":"The harvest plan skeleton","scenario":"Your harvest plan document has grown into eleven unordered sections: trucking, drying, field order, crew shifts, breakdown contingencies, elevator hours, safety, fuel, meals, weather triggers, custom help. Nobody can find anything in it, and it has no governing idea.","task":"Write the plan's one-sentence governing idea and the 3 section headings everything else files under.","tips":["The governing idea says what the whole plan optimizes: combine hours never wait on anything.","Three buckets maximum — people, machines, and grain flow is one honest cut.","Every orphan section must have a home or be cut."],"focus":["structure","clarity"]},
    {"id":"structure-agri-mid-05","level":"mid","profession":"agriculture","title":"Done, underway, decide","scenario":"Your weekly report to the owner reads like a diary — Monday this, Tuesday that. He keeps missing the decisions buried in the middle. You're rebuilding the template around what he needs: what's finished, what's moving, what needs him.","task":"Rewrite this week's report as three labeled sections — Done, Underway, Needs your call — one line each.","tips":["The 'Needs your call' section is why the report exists — never bury it.","One line per item; detail on request.","Same skeleton every week trains the reader where to look."],"focus":["structure","concision"],"placeholder":"Done: spraying finished on all wheat. Underway: —"},
    {"id":"structure-agri-mid-06","level":"mid","profession":"agriculture","title":"The safety meeting agenda","scenario":"Your monthly safety meeting notes are a grab bag: the ATV near-miss, PTO shields missing on two implements, heat protocol for July, the new eyewash station, first-aid kit restocking, a reminder about the grain-bin lockout rule. Twenty minutes, one agenda.","task":"Group the items into 3 themed agenda blocks and give each a heading.","tips":["Group by theme, not by when you thought of it: incidents to learn from, equipment fixes, seasonal prep.","Put the near-miss first — stories hold attention that rules don't.","Cut or defer anything that's an email, not a meeting item."],"focus":["structure","audience"]},
    {"id":"structure-agri-mid-07","level":"mid","profession":"agriculture","title":"One message, three legs","scenario":"You're pitching a new wholesale buyer on carrying your produce. You have a pile of selling points: third-generation farm, food-safety certified, 40-minute delivery distance, cold chain, flexible volumes, good prices. A pile isn't a pitch.","task":"Write the one governing message and the 3 supporting points you'd hang everything on.","tips":["The governing message answers the buyer's question: why is my life easier with you?","Three supports maximum — reliability, freshness, flexibility is one clean cut.","Every fact you keep must hold up one of the three legs."],"focus":["structure","impact"]},
    {"id":"structure-agri-mid-08","level":"mid","profession":"agriculture","title":"The equipment ramble, sorted","scenario":"Your shop lead's verbal status update was one long breath: combine's ready, the swather needs a belt that's on order, tractor 3 has a slow hydraulic leak we're watching, the drill is done, sprayer needs its annual service before June, grain cart tire ordered. You're writing it up for the owner.","task":"Reorganize the update into 3 groups with one-line headings, ready to send.","tips":["Group by what the reader does with it: ready, in progress with dates, needs a decision.","Order groups by urgency, not by machine size.","A date on every unfinished item."],"focus":["structure","precision"]},
    {"id":"structure-agri-mid-09","level":"mid","profession":"agriculture","title":"SCQA for switching seed suppliers","scenario":"You want to move the seed business from the dealer the owner has used for twenty years to a competitor: better varieties for your soils, 6% cheaper, and an agronomist who actually visits. The relationship history makes this a careful pitch, not a price announcement.","task":"Frame the case as SCQA, one sentence per element.","tips":["Situation honors the history: twenty good years is the starting fact, not the enemy.","Complication is what changed: our soils and their lineup have drifted apart.","The Question frames the decision you want asked — 'is loyalty costing us yield?'"],"focus":["structure","audience"]},
    {"id":"structure-agri-mid-10","level":"mid","profession":"agriculture","title":"Storm damage, organized","scenario":"Last night's windstorm left a mess: lodged barley in two fields, a torn machine-shed roof, a snapped power pole the utility owns, scattered irrigation pipe, and a shaken but unhurt night worker. Your notes to the owner are currently in the order you found things.","task":"Write a damage summary structured in 3 blocks: people, crop, infrastructure — one line each.","tips":["People first, always — even when the news is good.","Within each block: what happened, what it costs, what you're doing.","The reader should get the whole picture from the three headings alone."],"focus":["structure","clarity"],"placeholder":"People: everyone's fine — the night worker was clear of the shed when the roof went."},
    {"id":"structure-agri-mid-11","level":"mid","profession":"agriculture","title":"PREP on herd expansion","scenario":"A board member asks in the meeting: 'Should we grow the herd next year?' Your view is no — milk price outlook is flat, the barn is at capacity, and heifer prices are high. Unstructured, your answer would tour all three facts and land nowhere.","task":"Give a spoken PREP answer in 4 sentences: Point, Reason, Example, Point.","tips":["Point first: 'Not next year.'","Pick your strongest single reason; mention the others in passing at most.","The example makes it concrete: what one added stall actually costs right now."],"focus":["structure","clarity"],"placeholder":"Not next year — the numbers don't support it yet."},
    {"id":"structure-agri-mid-12","level":"mid","profession":"agriculture","title":"The hiring plan, grouped","scenario":"Your notes on labor needs are scattered: two tractor operators by April, six pickers July through September, a relief milker any time, maybe a shop hand if budget allows, and Rosa wants to move from picking to packing lead. It's going to the owner as the season's hiring plan.","task":"Organize the needs into a structure with 3 buckets and write the bucket headings.","tips":["Group by commitment: must hire with dates, contingent on budget, internal moves.","Sequence by when each decision is needed.","The 'maybe' items need a trigger, not a shrug — name what would confirm them."],"focus":["structure","precision"]},
    {"id":"structure-agri-mid-13","level":"mid","profession":"agriculture","title":"The vet visit, written up","scenario":"The vet spent two hours on the herd check and left you a wall of verbal findings: two pregnancies confirmed, one cow to recheck in two weeks, a lameness case needing a trim, a vaccine booster schedule, and a feed-ration suggestion. The owner and the herdsman both need the summary.","task":"Write the summary with a one-sentence governing takeaway and 3 grouped sections.","tips":["Governing line first: herd is healthy overall — three follow-ups scheduled.","Group by action owner: what the herdsman does, what you schedule, what the owner decides.","Dates on every follow-up."],"focus":["structure","clarity"]},
    {"id":"structure-agri-mid-14","level":"mid","profession":"agriculture","title":"The irrigation season on one page","scenario":"You're writing the irrigation plan for the season: allocation is down 10%, pivot 4's gearbox is suspect, the district's delivery schedule shifted, and you want to prioritize the seed-corn contract acres over the commodity fields. Right now it's four paragraphs of interleaved facts.","task":"Write the plan's governing idea in one sentence, then 3 section headings that carry the rest.","tips":["The governing idea is the priority rule: contract acres get water first.","Buckets could be: water budget, equipment risks, weekly schedule.","Interleaved facts are for conversations; documents need drawers."],"focus":["structure","clarity"],"placeholder":"Governing rule: the seed-corn contract acres never go short — everything else flexes."},
    {"id":"structure-agri-mid-15","level":"mid","profession":"agriculture","title":"The skipper's season debrief","scenario":"You're writing the season debrief for the boat's owner: catch was 8% under plan, fuel ran over, two gear failures cost four fishing days, crew retention was the best in years, and you have three specific asks for next season. Your draft is chronological — trip one, trip two, trip three.","task":"Restructure the debrief: one governing sentence plus 3 sections (results, causes, asks).","tips":["The governing sentence nets it out: a down year on catch, but the causes are fixable.","Trip-by-trip is data, not structure — group by theme.","Put the asks in their own section so they can't be skimmed past."],"focus":["structure","impact"]},
    {"id":"structure-agri-mid-16","level":"mid","profession":"agriculture","title":"The whiteboard that runs the day","scenario":"The shop whiteboard is where the crew looks first, and right now it's a scrawl of arrows and half-erased notes. You want a standing 3-column layout that answers a crew member's three morning questions without anyone asking you.","task":"Name the 3 columns and write one example line under each.","tips":["The columns answer: who's where today, what's broken or off-limits, what's coming tomorrow.","One line per item, readable from three metres away.","If a column needs a paragraph, it belongs in a conversation instead."],"focus":["structure","clarity","concision"]},
    {"id":"structure-agri-mid-17","level":"mid","profession":"agriculture","title":"One idea, three reasons","scenario":"The 30-year-old loader tractor is nickel-and-diming the farm to death, and you want to replace it this winter. Your evidence is a heap: $9,400 in repairs over two years, three harvest-week breakdowns, no cab heat, parts getting scarce, operator complaints. Time to build the pyramid.","task":"Write the one-sentence recommendation and the 3 reasons that hold it up, one line each.","tips":["Top line is the ask with the number: replace it this winter for about $60K used.","Sort the heap into 3 reasons: cost, reliability at the worst times, operator safety and comfort.","Weakest evidence gets cut, not appended."],"focus":["structure","impact"],"placeholder":"Recommendation: replace the loader tractor this winter — about $60K used."},
    {"id":"structure-agri-mid-18","level":"mid","profession":"agriculture","title":"The cost-share application","scenario":"You're applying for the conservation cost-share program to fund fencing that keeps cattle out of the creek. The form has one open box: 'Describe the project and its need.' You have facts everywhere — herd size, water quality, the district's priorities, costs — but no frame.","task":"Write the answer as Situation, Complication, and Ask — one or two sentences each.","tips":["Situation: cattle currently water at the creek along 800 metres of bank.","Complication ties to the program's goal, not just yours — bank erosion and water quality.","The ask is precise: cost, your share, timeline."],"focus":["structure","precision"]},
    {"id":"structure-agri-mid-19","level":"mid","profession":"agriculture","title":"Market-stand feedback, themed","scenario":"After the season you asked the three market-stand staff for feedback and got a pile of notes: card reader keeps dropping signal, customers ask for bags, Saturday setup is rushed, pricing signs confuse people, the new tent is great, two staff want earlier schedules. It's going in your season report.","task":"Group the feedback into 3 named themes with the items under each.","tips":["Theme by what fixes it: equipment, customer experience, staffing.","Positive feedback gets kept — it tells you what to protect.","End each theme with the one action you'll take."],"focus":["structure","clarity"]},
    {"id":"structure-agri-mid-20","level":"mid","profession":"agriculture","title":"The audit-prep memo","scenario":"The food-safety audit is in three weeks and your prep notes are chaos: water tests due, worker hygiene training to refresh, traceability logs to spot-check, the packing shed door seal to fix, mock recall to run. The crew leads need a memo that reads as a plan, not a worry list.","task":"Structure the memo: one governing sentence, then 3 sections with owners and dates.","tips":["Governing sentence sets the frame: we pass this audit by closing five gaps in three weeks.","Group gaps by type: records, facilities, training.","Every item gets a name and a date or it isn't a plan."],"focus":["structure","precision"],"placeholder":"We're audit-ready in three weeks if we close five gaps — here's who owns each."},
    {"id":"structure-agri-mid-21","level":"mid","profession":"agriculture","title":"PREP on the volume guarantee","scenario":"On a call, the buyer asks: 'Can you guarantee me the same volume next year?' The honest answer is mostly-yes-with-conditions: yes on acreage, dependent on water allocation, and you'd want a price adjustment clause. Unstructured, that comes out as a waffle.","task":"Give a spoken PREP answer in 4 sentences.","tips":["Point first, honestly framed: 'Yes on acres — with one condition we should design together.'","The reason names the real variable: water allocation.","Land the point again so the condition doesn't sound like a dodge."],"focus":["structure","clarity"],"placeholder":"Yes on acreage — with one condition we should build into the contract."},
    {"id":"structure-agri-mid-22","level":"mid","profession":"agriculture","title":"Maintenance triage, three drawers","scenario":"The maintenance list has become a dumping ground: sprayer boom sensor, shop door opener, tractor 3's leak, the grain dryer's pre-season service, a wobbling market-trailer wheel, augers to grease, the fuel-tank gauge. Some are urgent, some seasonal, some can wait for winter.","task":"Sort the list into Urgent / Before season / Winter shop time, and write the rule you used to sort.","tips":["The sorting rule is the real deliverable: 'urgent = affects safety or this week's work.'","A wobbling wheel on a road trailer is safety — urgency isn't about the machine's size.","Publishing the rule lets the crew sort future items without you."],"focus":["structure","clarity"]},
    {"id":"structure-agri-mid-23","level":"mid","profession":"agriculture","title":"The landowner's annual letter","scenario":"You farm 300 acres for an absentee landowner and owe her the annual letter. You have yields, what you spent on her drainage, the fertility program, next year's crop plan, and a rent conversation to open. Last year's letter rambled; she called twice to ask what it meant.","task":"Write the letter's structure: a one-sentence opening takeaway and 3 section headings.","tips":["Open with what she most wants to know: the land performed well and was cared for.","Sections by her questions: how the land did, what was invested in it, what's planned.","The rent conversation gets its own clearly-labeled section — never smuggled in."],"focus":["structure","audience"]},
    {"id":"structure-agri-mid-24","level":"mid","profession":"agriculture","title":"SCQA for the drainage investment","scenario":"You want the owner to tile-drain the 60 wet acres: they're planted last, yield 30% below the farm average, and drowned out entirely twice in five years. Tiling costs about $1,000 an acre. The owner sees only the price tag; you need the frame that makes it an investment.","task":"Write the SCQA, one sentence per element.","tips":["Situation: the 60 acres carry full costs every year.","Complication: they return 30% less and fail completely one year in three.","The Question you want in his head: 'what is NOT tiling costing me?'"],"focus":["structure","impact"],"placeholder":"Situation: the wet 60 costs as much to farm as our best ground."},
    {"id":"structure-agri-mid-25","level":"mid","profession":"agriculture","title":"The planting brief","scenario":"Spring planting starts Monday and you're briefing the three crew leads. Everything is in your head: field order, seed logistics, planter settings by field, refuel plan, who floats between crews, weather triggers for switching fields, and the daily check-in time. Fifteen minutes, one brief.","task":"Structure the brief: the one governing priority, then 3 blocks in the order you'd deliver them.","tips":["Governing priority first: the planter never stops — everything serves that.","Blocks by who acts on them: the plan, the support system, the change triggers.","Close with the check-in rhythm so coordination has a heartbeat."],"focus":["structure","clarity"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-agri-mid-01","level":"mid","profession":"agriculture","title":"The 400-word Friday email","scenario":"Your weekly email to the owner runs 400 words: weather recap, day-by-day activities, machinery notes, staff news, and somewhere in there, the two things that matter — spraying is done and the corn needs a side-dress decision. He skims it at best.","task":"Cut the report to under 100 words without losing either thing that matters.","tips":["Start by finding the two load-bearing sentences; build around only those.","Weather gets a clause, not a paragraph.","If a detail doesn't change what the owner does, it goes."],"focus":["concision","structure"]},
    {"id":"concise-agri-mid-02","level":"mid","profession":"agriculture","title":"The hedge-trimmed parts request","scenario":"Your draft to the equipment dealer: 'I was just wondering if maybe you might be able to check whether the hydraulic pump we talked about could possibly still be available, if it's not too much trouble.' You need the pump this week.","task":"Rewrite it as one direct sentence.","tips":["'Just wondering if maybe' is three hedges before the verb — cut all of them.","Direct is not rude; it's respectful of his time.","Add the deadline — that's the useful part your hedging displaced."],"focus":["concision","clarity"],"placeholder":"Is the hydraulic pump still available? I need it by Friday."},
    {"id":"concise-agri-mid-03","level":"mid","profession":"agriculture","title":"The radio sentence","scenario":"Harvest radio chatter: you need the grain-cart driver to switch to the west field after his current dump because combine 2 is nearly full. Your habit is a forty-word explanation of everyone's positions. Radio time is shared and the crew tunes out long calls.","task":"Say it in one sentence of 15 words or fewer.","tips":["Name, instruction, reason — in that order, then stop.","One instruction per call; the next one can wait.","If it takes a breath in the middle, it's too long."],"focus":["concision","clarity"],"placeholder":"Tomas — after this dump, head to the west field, combine 2's nearly full."},
    {"id":"concise-agri-mid-04","level":"mid","profession":"agriculture","title":"Kill the throat-clearing","scenario":"Your board report opens: 'In this report I will provide an overview of the quarter's operational activities, before moving on to discuss the financial picture and finally addressing some items requiring board attention.' Three lines of table-of-contents before any content.","task":"Delete the meta-commentary and write the opening sentence that starts with actual news.","tips":["Announcing what you'll say is not saying it.","Headings do the signposting a preamble pretends to do.","Open with the quarter's single most important fact."],"focus":["concision","impact"],"placeholder":"The quarter closed 6% under budget on costs, with harvest fully contracted."},
    {"id":"concise-agri-mid-05","level":"mid","profession":"agriculture","title":"Each and every redundancy","scenario":"Your safety briefing draft is padded with doubled words: 'each and every one of you', 'first and foremost', 'at this point in time', 'in the event that', 'full and complete stop.' The message underneath — shut off the PTO before leaving the tractor seat — is getting smothered.","task":"Rewrite the key instruction in two sentences with every redundant pair cut.","tips":["'Each and every' is 'every'; 'at this point in time' is 'now.'","Padding reads as authority to the writer and noise to the listener.","Short rules get repeated; long rules get forgotten."],"focus":["concision","clarity"]},
    {"id":"concise-agri-mid-06","level":"mid","profession":"agriculture","title":"Unbury the verbs","scenario":"You drafted for the crop plan: 'The implementation of the rotation of crops will result in the improvement of soil structure and the reduction of disease pressure.' Every action is buried in a noun. The plan reads like a permit application.","task":"Rewrite the sentence with real verbs doing the work.","tips":["'The implementation of the rotation' is 'rotating.'","Find the actor and let it act: rotation improves, rotating reduces.","Nominalizations add syllables and subtract energy."],"focus":["concision","clarity"],"placeholder":"Rotating crops will improve the soil and cut disease pressure."},
    {"id":"concise-agri-mid-07","level":"mid","profession":"agriculture","title":"The buyer text, trimmed","scenario":"Your draft text to the produce buyer runs six sentences: greetings, weather, a compliment on their new warehouse, and finally — Thursday's delivery moves to Friday, same volume. Texts get read in three seconds or saved for never.","task":"Cut it to two sentences that survive a three-second read.","tips":["The change and the new fact — that's the whole message.","Goodwill lives in reliability, not in padding.","End with the confirm question so it closes the loop."],"focus":["concision","clarity"],"placeholder":"Thursday's delivery moves to Friday, same volume. Does that still work for your dock?"},
    {"id":"concise-agri-mid-08","level":"mid","profession":"agriculture","title":"The whiteboard note","scenario":"You wrote on the shop whiteboard: 'Please be advised that the sprayer located in the east bay should not be operated at the present time due to an ongoing issue with the boom sensor which is currently awaiting a replacement part.' It takes up half the board.","task":"Rewrite it in eight words or fewer.","tips":["Whiteboards are for glances, not paragraphs.","Machine, status, done: 'Sprayer down — parts coming.'","'Please be advised' has never advised anyone."],"focus":["concision","clarity"],"placeholder":"SPRAYER DOWN — boom sensor. Parts due Wed."},
    {"id":"concise-agri-mid-09","level":"mid","profession":"agriculture","title":"The twenty-second voicemail","scenario":"Your voicemails to the vet clinic average ninety seconds: the animal's history, your theories, the weather, and eventually the ask. The clinic triages by voicemail, and rambles get returned last. Today: a down cow, fresh two weeks, you suspect milk fever.","task":"Script a voicemail under 20 seconds — roughly 40 words.","tips":["Who you are, the animal, the one-line picture, the ask, your number. Done.","Your theory is one clause, not a differential diagnosis.","Time yourself out loud — 20 seconds is shorter than you think."],"focus":["concision","precision"],"placeholder":"It's Sam at Miller Farm — down cow, fresh two weeks, looks like milk fever. Need a call back this morning: 555-0142."},
    {"id":"concise-agri-mid-10","level":"mid","profession":"agriculture","title":"The job post nobody finishes","scenario":"Your seasonal-picker job post runs 300 words, half of it about the farm's history and values. The people you want are reading it on a phone, comparing five farms. What they scan for: pay, dates, hours, housing, how to apply.","task":"Rewrite the post in five short lines.","tips":["Lead with pay — it's the first filter every applicant applies.","One line each: pay, dates, hours, housing, apply-here.","Farm story can live at the interview; it's not doing work in the post."],"focus":["concision","audience"]},
    {"id":"concise-agri-mid-11","level":"mid","profession":"agriculture","title":"The apology that buries the facts","scenario":"A delivery to the food hub will be a day late, and your draft is 70% apology: 'so sorry, we hate to do this, we know how disruptive this is, we really appreciate your patience and understanding.' The facts — new day, same order, no price change — are hidden in the syrup.","task":"Rewrite in 3 sentences: one clean apology, then facts.","tips":["Apologize once, clearly — repetition weakens it.","The reader's real question is 'what do I do now?' Answer it.","Groveling shifts the work of reassurance onto them."],"focus":["concision","impact"],"placeholder":"Sorry — Thursday's delivery will land Friday instead. Same order, same price."},
    {"id":"concise-agri-mid-12","level":"mid","profession":"agriculture","title":"The timesheet announcement","scenario":"Your huddle announcement about the new timesheet app has swollen: why the old system failed, the selection process, the payroll company's requirements, a philosophical note about accuracy. The crew needs three facts: what app, starting when, who helps them set it up.","task":"Cut the announcement to 3 sentences.","tips":["Lead with what changes for them Monday morning.","The history of the decision is management's business, not the huddle's.","Name the helper — 'see Rosa at lunch' ends confusion before it starts."],"focus":["concision","audience"]},
    {"id":"concise-agri-mid-13","level":"mid","profession":"agriculture","title":"Kind of, sort of, basically","scenario":"You recorded yourself giving the market update at the co-op meeting: 'So basically prices are kind of soft right now, and we're sort of thinking we might want to maybe hold some grain back.' Eleven filler words wrapping one decision.","task":"Rewrite the spoken line clean, and say it aloud once.","tips":["'Basically', 'kind of', 'sort of' — verbal packing foam. Remove it all.","A pause carries more authority than a filler.","The clean version: prices are soft, so we're holding grain. Practice the stop."],"focus":["concision","impact"],"placeholder":"Prices are soft, so we're holding 40% of the grain until spring."},
    {"id":"concise-agri-mid-14","level":"mid","profession":"agriculture","title":"The classified ad, halved","scenario":"Your for-sale listing for the old drill runs 120 words, most of it story: bought it in 2011, always shedded, the season it saved, why you're upgrading. Buyers scan listings for model, condition, price, and location — in about four seconds.","task":"Cut the listing to 40 words or fewer, keeping everything a buyer filters on.","tips":["Model and year first, price early, location last.","'Always shedded' earns its place — it's condition evidence, not story.","Sentiment doesn't transfer; specs do."],"focus":["concision","precision"]},
    {"id":"concise-agri-mid-15","level":"mid","profession":"agriculture","title":"The incident report, just the facts","scenario":"Your draft incident report about the loader bumping the fuel tank runs a full page: back-story on the yard layout, the operator's day, your reflections. The insurer and the file need facts: what, when, who, damage, injuries, cause, corrective action.","task":"Rewrite the report as 6 factual lines.","tips":["One line per question the file must answer.","Opinions and reflections go in the follow-up conversation, not the record.","Precise beats padded: '09:40, no injuries, tank dented, no leak.'"],"focus":["concision","precision"]},
    {"id":"concise-agri-mid-16","level":"mid","profession":"agriculture","title":"Three questions, unburied","scenario":"Your email to the agronomist wanders through the whole season before asking, in scattered places, whether to lower the seeding rate on the sandy field, whether the pH result justifies lime this fall, and if she can visit before the 20th. She answered one of the three last time.","task":"Rewrite the email as a one-line opener plus 3 numbered questions.","tips":["Number the questions — numbered lists get numbered answers.","One sentence of context per question, attached to that question.","The visit request is a question too; give it a date."],"focus":["concision","structure"],"placeholder":"Three quick questions before planting: 1) Sandy field —"},
    {"id":"concise-agri-mid-17","level":"mid","profession":"agriculture","title":"The pre-departure brief, tightened","scenario":"As skipper, your pre-departure safety brief has grown to ten rambling minutes, and the experienced deckhands visibly switch off — which means the new hand does too. The core is five points: survival-suit locations, man-overboard roles, the danger zones on deck, radio protocol, and who has the medical kit.","task":"Write the five points as one sentence each, deliverable in under two minutes.","tips":["One breath per point; detail lives in the drills, not the brief.","Order by what kills fastest: man-overboard roles before radio protocol.","Ask the new hand one check-question at the end — that's the real test."],"focus":["concision","clarity"]},
    {"id":"concise-agri-mid-18","level":"mid","profession":"agriculture","title":"The two-sentence cancellation","scenario":"You have to cancel the extra weekend picking crew because the buyer cut this week's order. Your draft to the labor contractor is a maze of maybes: 'circumstances beyond our control', 'we may potentially need to revisit', 'hopefully we can possibly resume.' He just needs the facts.","task":"Write the cancellation in two clear sentences.","tips":["Say the thing: no crew this weekend.","Give the one real reason and the honest outlook — next week is likely on.","Vague cancellations breed hopeful invoices."],"focus":["concision","clarity"],"placeholder":"We won't need the weekend crew — the buyer cut this week's order."},
    {"id":"concise-agri-mid-19","level":"mid","profession":"agriculture","title":"One caveat, not five","scenario":"Your yield line for the owner's banker reads: 'It would seem that yields could potentially be somewhat above average, although obviously it's early, and weather permitting, all else being equal, we might possibly see around 195 bushels.' One estimate, five hedges.","task":"Rewrite it with the number and exactly one honest caveat.","tips":["Stacked hedges read as either anxiety or evasion — pick your one real uncertainty.","A range is a cleaner hedge than five qualifiers: 190-200.","'Barring late frost' says more than 'weather permitting, all else equal.'"],"focus":["concision","precision"],"placeholder":"We're on track for 190-200 bushels, barring a late frost."},
    {"id":"concise-agri-mid-20","level":"mid","profession":"agriculture","title":"The meeting invite that says why","scenario":"Your standing invite for the Monday planning meeting has a description nobody reads: four sentences about alignment, coordination, and touching base on various operational matters. Nobody comes prepared because nothing specific is asked of them.","task":"Rewrite the description in 2 lines: what the meeting decides, what to bring.","tips":["A meeting description is a contract: decisions made, inputs required.","'Touch base' and 'align' describe no observable activity — cut them.","If you can't name what it decides, question the meeting."],"focus":["concision","clarity"]},
    {"id":"concise-agri-mid-21","level":"mid","profession":"agriculture","title":"Instructions for the milk truck driver","scenario":"The pickup route is changing while the lane is being regraded. Your note for the milk truck driver runs a paragraph of geography and apology. Drivers read notes taped to the tank room door in the dark at 4 a.m.","task":"Rewrite the note as 3 short numbered steps.","tips":["Number the steps in driving order: enter, park, leave.","Landmarks over descriptions: 'past the blue silo', not 'the previously discussed entrance.'","4 a.m. readers get ten words a step, maximum."],"focus":["concision","clarity"]},
    {"id":"concise-agri-mid-22","level":"mid","profession":"agriculture","title":"The fence-budget ask, halved","scenario":"Your request to the owner for fence repairs is 200 words: the history of the fence line, three past incidents, neighbourly relations, and a philosophical case for maintenance. Somewhere in it: $3,400, two weeks, before cattle turn out in May.","task":"Cut it to 60 words without losing the ask, the deadline, or the strongest reason.","tips":["Amount, deadline, one reason — the rest is trimming.","Your strongest reason is cattle on the highway; keep only that one.","History justifies budgets in meetings, not in asks."],"focus":["concision","impact"],"placeholder":"I need $3,400 for fence repairs on the road side, finished before May turnout."},
    {"id":"concise-agri-mid-23","level":"mid","profession":"agriculture","title":"Eight words on a sandwich board","scenario":"The farm stand's sandwich board currently reads: 'We are pleased to announce that fresh sweet corn is now available for purchase daily while supplies last.' Cars pass it at 60 km/h.","task":"Rewrite it in eight words or fewer for a moving reader.","tips":["Drive-by readers get two beats: what, and a reason to stop.","'Pleased to announce' is invisible at any speed.","Test: could you read it aloud before the car passes?"],"focus":["concision","impact"],"placeholder":"SWEET CORN — picked this morning."},
    {"id":"concise-agri-mid-24","level":"mid","profession":"agriculture","title":"The reply to a new buyer","scenario":"A grocery chain's local-sourcing manager emailed asking if you can supply squash this fall. Your draft reply spends four sentences on gratitude and enthusiasm before any substance. Busy buyers read replies for one thing: can you, how much, what price window.","task":"Write a 3-sentence reply that answers before it charms.","tips":["Sentence one: yes, volumes, and the window.","One sentence of warmth is plenty — and it lands better after substance.","End with the next step: a call this week, or a sample delivery."],"focus":["concision","clarity"],"placeholder":"Yes — we can supply 800-1,000 lb of butternut weekly, October through December."},
    {"id":"concise-agri-mid-25","level":"mid","profession":"agriculture","title":"The break-schedule memo, halved","scenario":"Your memo about the new heat-season break schedule runs 180 words, restating the regulation, the reasoning, the weather outlook, and management's commitment to wellbeing. The crew needs: breaks now every two hours, ten minutes, in the shade trailer, water provided, starting tomorrow.","task":"Cut the memo to 3 sentences that a crew lead can read aloud in the huddle.","tips":["Lead with the new rule, in shift-clock terms.","One clause on why — heat — is enough; nobody disputes summer.","Read it aloud once: if you stumble, cut again."],"focus":["concision","clarity","audience"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-agri-mid-01","level":"mid","profession":"agriculture","title":"Numbers for 'a good year'","scenario":"The owner asks how harvest wrapped up and your draft says it went 'really well, better than expected in most fields.' He can't take 'really well' to the banker — he needs bushels, acres, and the comparison to plan.","task":"Rewrite the summary with the actual yield, the plan, and the one field that broke the pattern.","tips":["Replace 'really well' with the number: 194 bu/ac against a 180 plan.","Name the exception — the low forty at 150 — so the average is honest.","One comparison beats three adjectives."],"focus":["precision","clarity"],"placeholder":"Corn averaged 194 bu/ac against our 180 plan — every field over except the low forty at 150."},
    {"id":"precision-agri-mid-02","level":"mid","profession":"agriculture","title":"'Soon' isn't a delivery date","scenario":"The restaurant buyer asked when the first strawberries land and your draft says 'soon, probably within a couple of weeks depending on weather.' She's building a menu — she plans by dates, not by 'probably.'","task":"Rewrite with a specific first-delivery date, or the date you'll be able to name one.","tips":["Commit to a date or a dated decision point: 'first flats June 10, confirmed by the 5th.'","Say what would move it — one clause, not a weather essay.","A date she can plan around beats an honest-sounding shrug."],"focus":["precision","clarity"],"placeholder":"First flats land June 10 — I'll confirm by the 5th once we see this week's heat."},
    {"id":"precision-agri-mid-03","level":"mid","profession":"agriculture","title":"The variety claim, skeptic-proofed","scenario":"You want to switch 400 acres to the new soybean variety and your pitch to the owner says it 'did great in the trial.' A skeptic asks: great compared to what, on how many acres, and was the ground comparable? Your draft answers none of it.","task":"Rewrite the claim so it survives a skeptical reading: side-by-side numbers, acres, and conditions.","tips":["Give the strip-trial pairing: 61 vs 55 bu/ac on the same field, same inputs.","Name the sample size — 30 acres each side — so it's not one lucky strip.","Pre-empt the skeptic by including what they'd demand before they ask."],"focus":["precision","impact"],"placeholder":"In our strip trial the new variety ran 61 bu/ac against 55 for our current one — same field, same inputs, 30 acres each."},
    {"id":"precision-agri-mid-04","level":"mid","profession":"agriculture","title":"What, So What, Now What on fuel","scenario":"Your monthly note to the owner says diesel spend was $9,400 and stops. The number sits there with no meaning: is that high, why, and what happens next? He's left to interpret and worry.","task":"Rewrite as three tight sentences: the What, the So What, and the Now What.","tips":["What: $9,400, up 18% on last May.","So what: it's the extra tillage passes on the wet fields, not price.","Now what: the change you're making and when the number normalizes."],"focus":["precision","structure"],"placeholder":"Fuel came in at $9,400, up 18% on last May. That's the extra tillage on the wet fields, not price."},
    {"id":"precision-agri-mid-05","level":"mid","profession":"agriculture","title":"'The cows are doing better'","scenario":"After a month of mastitis trouble, your update says the herd is 'doing much better.' The owner and the vet both need the same thing: the bulk-tank count, the trend across tests, and how far from the penalty line.","task":"Rewrite with the counts, the number of consecutive tests, and the margin to the threshold.","tips":["'Much better' becomes 210,000 down from 380,000 across three tests.","Three consecutive tests is what makes it a trend, not noise — say so.","Give the distance to the penalty line so 'better' has a ruler."],"focus":["precision","clarity"],"placeholder":"Bulk tank is down to 210,000 from 380,000 — three straight tests improving, and well under the 400,000 penalty line."},
    {"id":"precision-agri-mid-06","level":"mid","profession":"agriculture","title":"The yield-map data dump","scenario":"You're showing the owner this season's yield maps — thirty screens of red and green. He stares, waiting for you to tell him what they mean. The one insight — the headlands are costing 15 bushels everywhere — is buried in the colors.","task":"Write the single insight sentence the maps support, so the data serves a point.","tips":["Find the one thing thirty maps agree on.","Lead with that sentence; the maps become evidence, not the message.","If you can't say the insight in one line, the data isn't ready to show."],"focus":["precision","structure"],"placeholder":"Every map says the same thing: compacted headlands are costing us about 15 bu/ac on every field."},
    {"id":"precision-agri-mid-07","level":"mid","profession":"agriculture","title":"'Fishing's been slow'","scenario":"You're the skipper and the owner asks how the season's running. Your instinct: 'slow, the fish just aren't there like last year.' He's deciding whether to keep two boats fishing — he needs catch per tow, days at sea, and the comparison.","task":"Rewrite with the catch rate, the effort, and last season's baseline.","tips":["'Slow' becomes 1.1 tonnes per tow against 1.6 last season.","Include effort — same grounds, 20% more tows — so it's not an excuse.","Numbers let him make the two-boat call; adjectives don't."],"focus":["precision","clarity"],"placeholder":"We're averaging 1.1 tonnes a tow against 1.6 last season — same grounds, and we're towing 20% more to get it."},
    {"id":"precision-agri-mid-08","level":"mid","profession":"agriculture","title":"'The crew is faster this year'","scenario":"You told the owner the picking crew is 'way faster this year' to justify the returning-worker bonus. He raised an eyebrow. The claim needs bins per picker-day and the season-over-season comparison, or it reads as favoritism.","task":"Rewrite the claim with the rate, the baseline, and what it's worth in dollars.","tips":["'Way faster' becomes 9.5 bins per picker-day against 7.8 last year.","Convert the gap to money: fewer crew-days at harvest peak.","The bonus stops being a favor and becomes arithmetic."],"focus":["precision","impact"],"placeholder":"The returning crew is averaging 9.5 bins a day against 7.8 last year — that's about 11 fewer crew-days over the season."},
    {"id":"precision-agri-mid-09","level":"mid","profession":"agriculture","title":"Rain you can measure","scenario":"You're making the case for drainage tile on the east quarter and your draft says it 'floods badly almost every spring.' The owner has heard that for years. The rain gauge and the planting log can turn a complaint into evidence.","task":"Rewrite the case with measured rainfall, days late planting, and the yield gap on that quarter.","tips":["'Floods badly' becomes: three of the last four springs, planted 12-18 days behind the rest of the farm.","Tie the delay to the measured yield gap on that quarter.","Evidence from your own logs beats anyone's memory of the weather."],"focus":["precision","impact"],"placeholder":"The east quarter has planted 12-18 days behind the rest of the farm in three of the last four springs — and yields 20% under the farm average every one of those years."},
    {"id":"precision-agri-mid-10","level":"mid","profession":"agriculture","title":"'Docking us hard' at the elevator","scenario":"Your note to the owner says the elevator is 'docking us hard on the wheat.' He'll ask: how hard, on what grade factor, and what's it costing? You have the scale tickets to answer all three.","task":"Rewrite with the grade factor, the cents per bushel, and the total so far.","tips":["Name the factor: 15.8% moisture against a 14.5% line.","'Hard' becomes 22 cents a bushel — and $2,900 across the loads to date.","End with the lever: what drying or waiting would save."],"focus":["precision","clarity"],"placeholder":"The elevator is docking 22 cents a bushel for moisture — 15.8% against their 14.5% line. That's $2,900 across the loads so far."},
    {"id":"precision-agri-mid-11","level":"mid","profession":"agriculture","title":"'Feed is killing us'","scenario":"You want the owner to approve locking in feed contracts, and your draft opens with 'feed costs are killing us right now.' The claim needs a per-tonne price, the ration cost per cow per day, and the trend — or it's just a sigh.","task":"Rewrite with the current cost, the baseline, and what locking in would save.","tips":["'Killing us' becomes $8.10 per cow per day, up from $6.90 in January.","Multiply it out — the herd-level monthly number is what moves an owner.","Then the lever: the contract price and what it holds."],"focus":["precision","impact"],"placeholder":"Ration cost is $8.10 per cow per day, up from $6.90 in January — about $7,200 a month more across the herd."},
    {"id":"precision-agri-mid-12","level":"mid","profession":"agriculture","title":"The spray log an inspector reads","scenario":"Your crew lead's spray entry says 'sprayed the back field last week for bugs.' The organic inspector — and the label law — need product, rate, date, wind, and applicator. One vague entry can unravel an audit.","task":"Rewrite the entry with every fact an inspector checks, in one clean line.","tips":["The five facts: date, field, product and rate, wind speed and direction, who sprayed.","Write it the day it happens — 'last week' is the tell of a reconstructed log.","An entry that answers every question stops the audit from digging."],"focus":["precision","audience"],"placeholder":"June 4, Field 9 east half — Entrust at 6 oz/ac, wind SW 8 km/h, applied by M. Torres, 6:10-7:40 a.m."},
    {"id":"precision-agri-mid-13","level":"mid","profession":"agriculture","title":"'The combine's been unreliable'","scenario":"You're building the case to replace the older combine and your draft says it's 'been unreliable all fall.' The owner will defend the machine he bought. Hours down, acres lost to weather, and repair bills make the case you can't argue with.","task":"Rewrite with downtime hours, the harvest days lost, and the season's repair total.","tips":["'Unreliable' becomes 31 hours down across six breakdowns.","Tie downtime to consequence: the 90 acres that took rain because of it.","Add the repair total — the machine argues for its own replacement."],"focus":["precision","impact"],"placeholder":"The 9600 was down 31 hours across six breakdowns this fall — that's the 90 acres that caught rain, plus $11,400 in repairs."},
    {"id":"precision-agri-mid-14","level":"mid","profession":"agriculture","title":"Evidence for the raise","scenario":"Your irrigation tech deserves a raise and your note to the owner says he's 'been outstanding this season.' Outstanding is an opinion. What he did — and what it saved — is a case.","task":"Rewrite the recommendation with two or three measurable things he did and what each was worth.","tips":["Swap 'outstanding' for the specifics: caught the pump bearing before it seized, rebuilt pivot 4 in-house.","Put a number on each — the custom-shop quote he saved, the corn the early catch protected.","A raise justified by arithmetic survives the owner's second thoughts."],"focus":["precision","impact"],"placeholder":"Dan caught the pump bearing before it seized — a $9,000 rebuild and a week of dry corn if it had let go mid-July."},
    {"id":"precision-agri-mid-15","level":"mid","profession":"agriculture","title":"'We thinned enough'","scenario":"The orchard owner asks whether the apple thinning crew got the crop load right. Your gut says yes, but 'looks about right to me' won't hold if fruit size disappoints in September. You counted fruitlets on sample limbs.","task":"Write a 2-sentence answer built on the counts, not the gut.","tips":["Give the sample numbers: 4-6 fruitlets per limb section against a 5 target.","Say how many trees you counted — the sample is the credibility.","'Looks right' plus a count becomes 'is right.'"],"focus":["precision","clarity"],"placeholder":"We're at 4-6 fruitlets per limb section against a target of 5, counted across 40 trees in every block."},
    {"id":"precision-agri-mid-16","level":"mid","profession":"agriculture","title":"Ahead on the cut block — by how much?","scenario":"You run the forestry crew and the owner asks how the cut block is tracking. Your draft text says 'ahead of schedule, going well.' He's scheduling the trucks and the next block — he needs cubic metres and a finish date.","task":"Write a 2-sentence reply with volume against plan and the projected finish.","tips":["'Ahead' becomes 3,100 m³ cut against a 2,800 plan for this point.","Convert the pace to a date: done by the 22nd at current production.","The trucks get scheduled off your numbers, not your mood."],"focus":["precision","concision"],"placeholder":"We're at 3,100 m³ against a plan of 2,800 by now — on this pace the block finishes the 22nd."},
    {"id":"precision-agri-mid-17","level":"mid","profession":"agriculture","title":"Date the delivery commitment","scenario":"The elevator asked when your canola comes in and you said 'sometime after harvest wraps, we'll see how it goes.' They allocate dump space by commitments. Vague answers get you the worst slots in the busiest week.","task":"Rewrite the commitment with loads, dates, and the condition that could move them.","tips":["Commit: 12 loads, October 6-10, pending a dry week before.","Name the one condition honestly — don't pad with three.","A dated commitment gets you the slot; 'we'll see' gets you the queue."],"focus":["precision","clarity"],"placeholder":"Plan on 12 loads of canola October 6-10 — the only thing that moves it is if we lose this coming week to rain."},
    {"id":"precision-agri-mid-18","level":"mid","profession":"agriculture","title":"The drip-system savings claim","scenario":"You championed the drip conversion and now tell the owner it's 'saving a ton of water.' He paid $60,000 for it; he wants the meter readings. You have last year's flood-irrigated usage and this year's metered numbers for the same block.","task":"Write a 2-3 sentence claim with the baseline, the metered number, and what it's worth.","tips":["Give both readings: 14 inches applied this year against 22 last, same block, similar heat.","Note the condition match so the skeptic can't wave it away.","Convert to pumping cost — the savings should speak in dollars too."],"focus":["precision","impact"],"placeholder":"The drip block used 14 inches this season against 22 under flood last year — similar heat — and cut pumping cost about $3,800."},
    {"id":"precision-agri-mid-19","level":"mid","profession":"agriculture","title":"The soil test without a verdict","scenario":"You forwarded the soil-test results to the owner as-is: twelve fields of P, K, and pH numbers. He replied 'so what am I looking at?' The insight — three fields are mining their phosphorus and need a correction — never made it into words.","task":"Write the 2-sentence cover note that states the insight and the action, with the data as backup.","tips":["Lead with the verdict: three fields are running down their P and it will cost yield within two seasons.","Name the action and price: a correction pass this fall, about $28/ac on those fields.","Data attached, insight up front — never make the reader do the analysis."],"focus":["precision","structure"],"placeholder":"Three fields — 4, 7, and 11 — are mining their phosphorus and will start costing yield within two seasons."},
    {"id":"precision-agri-mid-20","level":"mid","profession":"agriculture","title":"'Losing more calves than usual'","scenario":"You tell the owner you're 'losing more calves than usual this spring.' Before the vet call and the protocol review, that feeling needs to be a rate: how many, out of how many born, over what window, against what's normal for the herd.","task":"Rewrite with the count, the rate, the window, and the baseline.","tips":["'More than usual' becomes 6 of 84 born since March — 7% against your usual 3.","A defined window keeps the number honest.","The rate is what the vet triages on; the feeling is what made you check."],"focus":["precision","clarity"],"placeholder":"We've lost 6 of 84 calves born since March 1 — about 7%, when our normal run is 3%."},
    {"id":"precision-agri-mid-21","level":"mid","profession":"agriculture","title":"The better price, netted out","scenario":"You want to haul this year's oats to the farther buyer because 'their price is better.' The owner's first question: better by how much, and what does the extra trucking eat? Do the netting before he asks.","task":"Write a 2-sentence case with both prices, the freight difference, and the net per bushel.","tips":["Both numbers side by side: $4.85 there against $4.60 here.","Subtract the freight honestly — 11 cents — and give the net gain.","Multiply by the crop so the decision has a total on it."],"focus":["precision","impact"],"placeholder":"Northgate is paying $4.85 against $4.60 local; extra trucking costs 11 cents, so we net 14 more a bushel — about $6,300 on the crop."},
    {"id":"precision-agri-mid-22","level":"mid","profession":"agriculture","title":"A range, not a guess","scenario":"The co-op board asks for your yield forecast in July. False precision — '187 bu/ac' — will be quoted back at you in October. Vagueness — 'should be decent' — helps no one. The craft is a defensible range with its basis.","task":"Write a 2-sentence forecast: the range, what it's based on, and what would move it.","tips":["Give a range you'd defend: 180-195, based on stand counts and normal August rain.","Name the swing factor — August rain — so the range has a hinge.","A range with a basis reads as judgment; a point estimate reads as bravado."],"focus":["precision","audience"],"placeholder":"I'm forecasting 180-195 bu/ac, based on stand counts and average August rain — a dry August takes us to the bottom of that."},
    {"id":"precision-agri-mid-23","level":"mid","profession":"agriculture","title":"'Pruning took forever'","scenario":"Reviewing the season with the owner, you say pruning 'took forever this year.' If you want him to fund the hedger attachment, 'forever' has to become hours per acre against last year, and a labor bill.","task":"Rewrite with hours per acre, the comparison, and the cost of the difference.","tips":["'Forever' becomes 26 hours an acre against 19 last season.","Explain the driver in one clause — the frost-damaged wood.","End with what the hedger changes, in the same units."],"focus":["precision","concision"],"placeholder":"Pruning ran 26 hours an acre against 19 last year — the frost wood did it — which was about $9,000 in extra labor."},
    {"id":"precision-agri-mid-24","level":"mid","profession":"agriculture","title":"Evidence for the hail claim","scenario":"The adjuster will visit Thursday for the hail claim on the apples. Your notes say 'lots of damage across the orchard.' Claims are paid on counted evidence: strikes per hundred fruit, by block, with dated photos.","task":"Write the 2-3 sentence damage summary you'll hand the adjuster, built on counts.","tips":["'Lots' becomes 35-40 strikes per hundred fruit in the north blocks, 10-15 in the south.","Say how you sampled — 100 fruit per block, four blocks — so the numbers stand up.","Dated photos of each count turn your summary into a file, not a story."],"focus":["precision","clarity"],"placeholder":"North blocks are showing 35-40 hail strikes per hundred fruit, south blocks 10-15 — counted on 100-fruit samples per block, photos dated the morning after."},
    {"id":"precision-agri-mid-25","level":"mid","profession":"agriculture","title":"The fuel burn that proves the problem","scenario":"You've told the boat's owner the main engine is 'burning more fuel than it should.' He hears that as skipper's grumbling. The fuel log across the last six trips, against the same trips last year, is the evidence that gets the injector job approved.","task":"Write a 2-3 sentence case with litres per hour, the baseline, and the cost per trip.","tips":["'More than it should' becomes 34 L/hr against last season's 29 on the same runs.","Multiply the gap by trip hours — the per-trip dollar figure is the argument.","End with the ask: the injector service and what it costs against three trips of waste."],"focus":["precision","impact"],"placeholder":"The main is burning 34 litres an hour against 29 last season on the same runs — about $480 extra per trip, and the injector service pays for itself in three."}
  ],
  "executive-presence": [
    {"id":"presence-agri-mid-01","level":"mid","profession":"agriculture","title":"Own the combine pick","scenario":"The owner asked which of two used combines to buy. Your draft lays them out neutrally — 'the 2019 has lower hours but costs more; the 2016 is cheaper but nearer a rebuild' — and leaves the choice to him. He asked you because you'll run the machine.","task":"Rewrite to lead with your recommendation and own it, with the options as support.","tips":["State your pick in sentence one — you have a view, so give it.","A neutral menu hands your job back to the owner.","Give the trade-off, then say which side you land on and the one reason why."],"focus":["impact","structure"],"placeholder":"I'd buy the 2019 — the extra $30K buys us three seasons before major work instead of one."},
    {"id":"presence-agri-mid-02","level":"mid","profession":"agriculture","title":"Signpost the board update","scenario":"You're opening the quarterly update to the co-op board and your habit is to dive straight into field-by-field detail. A manager with presence tells the room the shape first: how many parts, what they are, and the bottom line up front.","task":"Write the 2-3 sentence opening that frames the update and states your bottom line first.","tips":["Signal the structure: three things — harvest results, the dryer project, one decision needed.","Give the verdict now: on plan, one item needing a vote.","Telling them where you're going is what confidence sounds like."],"focus":["structure","impact"],"placeholder":"Three things today: harvest results, the dryer project, and one decision I need from you. Bottom line — we're on plan, and the decision is about next year's seed contract."},
    {"id":"presence-agri-mid-03","level":"mid","profession":"agriculture","title":"The hedged replant call","scenario":"Frost took out a third of the canola stand and the owner wants your call: replant or keep it. Your draft says 'it could honestly go either way, there are arguments on both sides.' True of everything — and useless to him.","task":"Rewrite to state your call plainly, with the one reason that decides it.","tips":["Make the call: keep the stand.","'Arguments both ways' describes every decision ever made — say where you land.","One decisive reason — the calendar — beats a balanced non-answer."],"focus":["impact","clarity"],"placeholder":"Keep the stand. Two-thirds of a May crop beats a full stand seeded in June — the calendar decides this one."},
    {"id":"presence-agri-mid-04","level":"mid","profession":"agriculture","title":"Stop hiding behind the agronomist","scenario":"You agree with the fungicide pass but your note to the owner says 'the agronomist thinks we should maybe consider spraying.' You've attributed the call to someone else and softened it twice. If you believe it, own it.","task":"Rewrite the recommendation in your own voice, with the agronomist as evidence, not shield.","tips":["Say 'I recommend spraying' — the agronomist's scouting is your supporting evidence.","'Thinks we should maybe consider' is three hedges deep; strip all of them.","You own the outcome either way, so own the call too."],"focus":["impact","clarity"],"placeholder":"I recommend we spray the wheat this week — scouting confirmed rust on the lower leaves, and waiting costs more than the pass."},
    {"id":"presence-agri-mid-05","level":"mid","profession":"agriculture","title":"Steady after the shop fire","scenario":"An electrical fire gutted the equipment shop overnight. Nobody was hurt, insurance is notified, and planting starts in three weeks. You're calling the owner, rattled, and if you sound panicked he'll panic too.","task":"Script a calm 4-sentence briefing: what happened, current state, next step, and your recommendation.","tips":["Facts first, in order — a steady voice is half the message.","Current state plainly: out, contained, nobody hurt, insurer called.","End owning the next step, not asking what to do."],"focus":["structure","impact"]},
    {"id":"presence-agri-mid-06","level":"mid","profession":"agriculture","title":"Fact and judgment, untangled","scenario":"The custom sprayer showed up two days late for the second time and your note to the owner reads 'they blew us off again, they clearly don't care about our business.' The fact is strong; the editorial wrapped around it makes the whole thing dismissible.","task":"Rewrite separating the facts from your judgment, each clearly labeled.","tips":["Facts first, clean: booked Tuesday, arrived Thursday, second time this season.","Then your read, marked as yours: 'my read is we're their lowest priority.'","Blend the two and the owner can dismiss the fact along with the opinion."],"focus":["clarity","impact"],"placeholder":"The sprayer was booked for Tuesday and arrived Thursday — second time this season. My read: we're their lowest-priority account, and I'd start pricing alternatives."},
    {"id":"presence-agri-mid-07","level":"mid","profession":"agriculture","title":"The call to run for port","scenario":"You're the skipper, the forecast has turned, and you've decided to cut the trip short and run for port with a half-full hold. Your radio call to the owner keeps wanting to apologize and re-litigate the decision. State it like the captain you are.","task":"Write the 2-sentence call that states the decision and the reason, without hedging or apology.","tips":["The decision is made — announce it, don't audition it.","One reason: the front is arriving faster than forecast.","Apologizing for a safety call teaches the owner to argue with the next one."],"focus":["impact","concision"],"placeholder":"We're running for port tonight — the front's coming in faster than forecast and I'm not working a deck in that."},
    {"id":"presence-agri-mid-08","level":"mid","profession":"agriculture","title":"Own the missed window","scenario":"Planting finished eight days late and cost yield potential. Presenting the season review, your draft says 'the team felt the wet spring made things difficult.' You made the sequencing calls. Owning it reads stronger than hiding in the weather and the crew.","task":"Rewrite the review line owning the decision in the first person, with the fix.","tips":["Say 'I sequenced the fields wrong,' not 'conditions were challenging.'","Owning the miss buys credibility the weather excuse never will.","Follow immediately with what changes next spring — decisively."],"focus":["impact","clarity"],"placeholder":"We planted eight days late, and part of that is on me — I sequenced the wet fields first. Next spring we start on the ridges and let the low ground wait."},
    {"id":"presence-agri-mid-09","level":"mid","profession":"agriculture","title":"The capital ask, unapologetic","scenario":"You're closing the pitch for the $85,000 grain dryer and your draft ends with 'anyway, sorry for the long email, no pressure, whatever you think is best.' Three sentences of retreat after two pages of good case.","task":"Rewrite the closing 2 sentences to end with a clear ask and a date.","tips":["End on the ask: approve it by Friday to catch the pre-season pricing.","Delete every apology — the case earned its length.","'Whatever you think is best' surrenders the recommendation you just made."],"focus":["impact","concision"],"placeholder":"I recommend we order the dryer by Friday to lock the pre-season price. Can I get your yes by Thursday?"},
    {"id":"presence-agri-mid-10","level":"mid","profession":"agriculture","title":"Cut the self-sabotage","scenario":"Your message to the owner opens 'this might be a dumb idea, and you've probably already thought of it, but...' before proposing a genuinely good custom-grazing arrangement. You've told him twice not to take it seriously before he's read it.","task":"Rewrite the opening sentence with the qualifiers stripped and the idea leading.","tips":["Delete 'dumb idea,' 'probably already thought of it,' and 'just.'","Lead with the proposal and its number.","Let the idea be judged on its merits — don't sentence it first."],"focus":["impact","concision"],"placeholder":"I want to propose custom-grazing the Hendersons' 60 heifers on our fall pasture — roughly $11,000 of income against grass we're not using."},
    {"id":"presence-agri-mid-11","level":"mid","profession":"agriculture","title":"Confident, not cocky, on the forecast","scenario":"The owner asks if you'll hit the yield budget. Overclaiming — 'absolutely, no question' — sets you up for October. Mush — 'hopefully, fingers crossed' — sounds like you're not in control. Calibrated confidence names the number, the basis, and the hinge.","task":"Write a 2-sentence answer that commits to a view while naming what would change it.","tips":["Commit: 'on track to beat budget' — then the basis, stand counts and moisture.","Name the single hinge: an early frost is the one thing that changes my answer.","Calibration is a strength signal; both bravado and mush are weakness signals."],"focus":["impact","precision"],"placeholder":"We're on track to beat budget — stands are strong and subsoil moisture is there. The one thing that changes that answer is a frost before mid-September."},
    {"id":"presence-agri-mid-12","level":"mid","profession":"agriculture","title":"Disagreeing with the vet","scenario":"The vet wants to treat the lame cows one at a time as they show; you think the whole pen needs a footbath protocol — you've seen this pattern before. You need to push back on a professional without either caving or lecturing.","task":"Write 2-3 sentences that state your view firmly, with your evidence, while keeping the vet's expertise in the room.","tips":["State the disagreement as a view, not an attack: 'I read this differently.'","Your evidence is the pattern — four new cases in ten days, all one pen.","Propose the test that settles it rather than demanding surrender."],"focus":["impact","audience"],"placeholder":"I read this differently — four new cases in ten days, all from pen 3, looks like a pen problem, not cow problems. Can we run the footbath protocol for two weeks and see if new cases stop?"},
    {"id":"presence-agri-mid-13","level":"mid","profession":"agriculture","title":"Signpost the safety stand-down","scenario":"After a near-miss with the auger, you're pulling the whole crew in for a stand-down talk. Nervous leaders ramble at these. The crew needs the shape in the first breath: what happened, what changes, what you're asking of them.","task":"Write the 2-3 sentence opening that frames the talk before diving in.","tips":["Frame it: 'Three things — what happened yesterday, one rule that changes today, and what I need from each of you.'","The frame lowers the room's temperature; rambling raises it.","Say the near-miss plainly — soft-pedaling it undercuts the whole talk."],"focus":["structure","clarity"]},
    {"id":"presence-agri-mid-14","level":"mid","profession":"agriculture","title":"Own the hiring recommendation","scenario":"Two candidates want the herdsman job. Your summary to the owner describes each fairly and ends 'happy to discuss whenever.' You've interviewed both, checked references, watched them work a shift. You know who it should be.","task":"Rewrite to recommend one by name, with the deciding reason and the risk you're accepting.","tips":["Name your pick in the first sentence.","Give the deciding factor — calm hands in the parlor beats two more years of experience.","Name the trade-off you're accepting so the owner knows you saw it."],"focus":["impact","structure"],"placeholder":"Hire Elena. She handled the fresh cows better in one shift than most do in a year — the trade-off is we'll train her on the feed system, and that's four weeks."},
    {"id":"presence-agri-mid-15","level":"mid","profession":"agriculture","title":"Shape the drought answer","scenario":"At the co-op meeting someone asks, 'So what's your plan if this dry spell runs another month?' Your instinct is to think out loud through every scenario. A shaped answer — three moves, in order — is what presence sounds like under uncertainty.","task":"Write the 3-sentence answer: the frame, then the three moves in the order they'd trigger.","tips":["Open with the shape: 'Three moves, in order, depending how long it runs.'","Each move gets one sentence and a trigger point.","Thinking out loud is for your truck cab; the meeting gets the finished thought."],"focus":["structure","concision"],"placeholder":"Three moves, in order. First, we're already grazing the hay regrowth and saving the silage. If it runs past July, we cull the bottom ten percent of the herd; past August, we buy feed early before the whole district is bidding on it."},
    {"id":"presence-agri-mid-16","level":"mid","profession":"agriculture","title":"Quote the price without flinching","scenario":"A new buyer asks your price on the second-cut hay. Your habit: '$9 a bale... but I mean, we could probably work something out, whatever works.' You've negotiated against yourself before he's said a word.","task":"Write the 1-2 sentence quote that states the price and stands on it.","tips":["State the price and one line of what backs it: barn-stored, no rain.","Then stop talking — the silence after a price is where deals are won.","Discounts you volunteer are discounts nobody asked for."],"focus":["impact","concision"],"placeholder":"Second cut is $9 a bale — barn stored, never rained on. That's the price whether you take fifty or four hundred."},
    {"id":"presence-agri-mid-17","level":"mid","profession":"agriculture","title":"Thirty seconds with the produce buyer","scenario":"You finally got the regional grocery buyer on the phone. You have thirty seconds of her attention before she decides whether the call continues. Who you are, what you grow, and what you're asking — in that order, no warm-up laps.","task":"Write the 3-sentence opening of the call.","tips":["Sentence one: name, farm, and the crop volume you can commit.","Sentence two: the one thing that makes you worth a slot — proximity, certification, season length.","Sentence three: the specific ask — a trial order, a meeting, a spec sheet review."],"focus":["structure","audience"],"placeholder":"This is Sam Reyes at Crosswind Farm — we grow 40 acres of greenhouse tomatoes twenty minutes from your Kelowna DC. I'm asking for one trial pallet a week in August so your produce manager can judge them against what's trucking in from three days away."},
    {"id":"presence-agri-mid-18","level":"mid","profession":"agriculture","title":"'We'll try our best' is not a commitment","scenario":"The packer asked if you can deliver all contracted potatoes by October 20. Your draft says 'we'll try our best, fingers crossed on weather.' Trying is not a plan. Either commit with a condition, or renegotiate the date — mush does neither.","task":"Rewrite as a real commitment with its one condition, or a clear counter-date.","tips":["'We'll try' becomes 'we will, unless' — with the condition named.","If you can't commit, propose the date you can: that's still decisive.","Mush feels safe to send and costs you the relationship when it fails."],"focus":["clarity","impact"],"placeholder":"We'll have the full contract delivered by October 20 unless we lose more than four days to rain — if that happens, you'll know by the 10th and the balance lands by the 25th."},
    {"id":"presence-agri-mid-19","level":"mid","profession":"agriculture","title":"The director who farms your farm","scenario":"A co-op board director interrupts your update: 'When I was running cattle we never needed a nutritionist, seems like an expensive fashion.' The room watches. Getting defensive loses; folding loses. Calm ownership of the decision wins.","task":"Write the 2-3 sentence response that holds the position with respect and one hard number.","tips":["Acknowledge without groveling: 'It's a fair challenge.'","One number carries the reply: the feed savings against the fee.","Hold the decision as yours — 'I'd make the same call again' — without heat."],"focus":["impact","audience"],"placeholder":"Fair challenge. The ration rebalance is saving about $60 a day in feed against a $9,000 annual fee — I'd make the same call again at twice the price."},
    {"id":"presence-agri-mid-20","level":"mid","profession":"agriculture","title":"Report your own mistake","scenario":"You misread the boundary and sprayed a 30-foot strip of the neighbor's hay. He hasn't noticed yet. The strong move is reporting it to the owner now, plainly, with the fix already in motion — not hoping it stays quiet.","task":"Write the 3-sentence report: what you did, what it means, what you've already done about it.","tips":["Say it without cushioning: 'I sprayed thirty feet over the line — my mistake.'","The impact honestly sized: his hay, one cutting, roughly an acre.","Actions already taken do the reassuring — you've called the neighbor and priced the make-good."],"focus":["impact","clarity"],"placeholder":"I oversprayed our west line by about thirty feet into Kowalski's hay — my mistake, roughly an acre affected. I've already called him and offered to cover the cutting."},
    {"id":"presence-agri-mid-21","level":"mid","profession":"agriculture","title":"The replant memo that decides","scenario":"Ten acres of the orchard's oldest variety loses money most years. Your memo to the owner lists three options — keep, graft over, replant — each with pros and cons, none with your name behind it. Option lists without a recommendation are analysis, not management.","task":"Rewrite the memo's opening to recommend one option, with the others as considered-and-set-aside.","tips":["Lead: 'I recommend replanting the ten acres to Ambrosia, starting this fall.'","One sentence each on why the other two lose.","'Considered and rejected' shows rigor better than false balance does."],"focus":["structure","impact"],"placeholder":"I recommend we replant the ten acres to Ambrosia starting this fall. Grafting over saves a year but marries us to old rootstock; keeping it loses $8-12K in an average year."},
    {"id":"presence-agri-mid-22","level":"mid","profession":"agriculture","title":"The wind call on the block","scenario":"Gusts are hitting 70 km/h in the cut block and you're shutting down falling for the day. Your radio call to the crew needs to be one decisive sentence — not a discussion opener. Some of them are paid by volume and will want to argue.","task":"Write the 1-2 sentence radio call that ends the workday without opening a negotiation.","tips":["The decision leads: 'Falling's done for the day — winds are over limit.'","Give the next instruction so momentum has somewhere to go: buck and deck what's down.","Decisive and calm; the piece-rate argument happens tomorrow, not on the radio."],"focus":["clarity","concision"]},
    {"id":"presence-agri-mid-23","level":"mid","profession":"agriculture","title":"End the email with a decision request","scenario":"Your emails to the owner end with 'let me know your thoughts when you get a chance.' Weeks pass. Thoughts are not what you need — you need a yes on the fertilizer prebuy by a date, or the price moves.","task":"Rewrite the closing sentence to request a specific decision by a specific date.","tips":["Name the decision and the date: 'I need your yes or no on the prebuy by Friday noon.'","Say what happens if the date passes — the price expires.","'Thoughts?' invites a conversation; a dated question invites an answer."],"focus":["impact","concision"],"placeholder":"I need a yes or no on the prebuy by Friday noon — the quoted price expires Monday and current market is 6% higher."},
    {"id":"presence-agri-mid-24","level":"mid","profession":"agriculture","title":"Ask for the authority","scenario":"Every repair over $500 waits on the owner's approval, and this season that lag cost two days of harvest. You're asking him to raise your spending authority to $5,000. Your draft grovels — 'I know it's your money and I completely understand if not.'","task":"Write the 2-3 sentence ask framed as a business case, not a favor.","tips":["Lead with what the current limit cost: two harvest days waiting on approvals for a $900 belt and a $1,200 sensor.","Make the ask precise: $5,000 authority for in-season repairs, every invoice still visible to him.","Confidence here is evidence plus a clean ask — not apology."],"focus":["impact","audience"],"placeholder":"The $500 approval limit cost us two harvest days this fall waiting on sign-offs for a belt and a sensor. I'm asking for $5,000 authority on in-season repairs — you still see every invoice, we just stop losing days to time zones."},
    {"id":"presence-agri-mid-25","level":"mid","profession":"agriculture","title":"Steady the panicking owner","scenario":"Canola dropped forty dollars a tonne this week and the owner is texting in all caps about selling everything today. You think panic-selling the whole crop at the bottom is the mistake. Your reply has to be steady, structured, and honest about what you don't control.","task":"Write the 3-sentence reply: acknowledge, state your read, and give the plan with its trigger points.","tips":["Meet the emotion in half a sentence, then get to the plan.","Your read, owned: 'I wouldn't sell it all into this dip.'","Structure calms: a third now, a third at your target, a third held — with the numbers."],"focus":["impact","clarity"],"placeholder":"I see it — ugly week. I wouldn't sell everything into this dip: I'd move a third now to take the pressure off, a third at $640 if it recovers, and hold the rest until January."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-agri-mid-01","level":"mid","profession":"agriculture","title":"'Yes or no — done before the rain?'","scenario":"The owner calls at noon: 'Will the wheat be off before Saturday's rain — yes or no?' Your instinct is to walk him through moisture, machine capacity, and the forecast models. He asked a yes/no.","task":"Give the direct answer first, then the single caveat that matters.","tips":["Answer yes or no before anything else.","One caveat — the load-bearing one — not the whole risk register.","Explaining before answering reads as dodging, even when it isn't."],"focus":["clarity","concision"],"placeholder":"Yes — as long as the dryer keeps up and we run past dark Thursday."},
    {"id":"pressure-agri-mid-02","level":"mid","profession":"agriculture","title":"The fuel bill challenge","scenario":"At the board meeting a director asks sharply: 'Why is fuel up thirty percent when everyone else's costs are flat?' Defending yourself invites a pile-on. Owning the number and giving the two real drivers closes it.","task":"Write the 2-3 sentence answer that owns the number and explains it with specifics.","tips":["Don't argue the thirty percent — it's real; own it first.","Two drivers, named: the extra tillage on the flooded quarter and the price spike in April.","End with what next year looks like, so the answer has a floor under it."],"focus":["clarity","impact"],"placeholder":"The thirty percent is real, and two things drove it: the flooded east quarter took three extra passes, and we bought April fuel at the spike."},
    {"id":"pressure-agri-mid-03","level":"mid","profession":"agriculture","title":"'What's killing the calves?'","scenario":"The owner asks point-blank what's causing the calf losses. The lab results are three days out and you genuinely don't know. The temptation is to guess — scours, probably? — to sound in control. A wrong guess now poisons every answer later.","task":"Write the 2-sentence answer that says you don't know yet, with the path and the date.","tips":["Say it plainly: 'I don't know yet, and I won't guess.'","Give the path: samples at the lab, results Thursday, vet on standby.","'I don't know, and here's how I'll know by when' is a strong answer."],"focus":["clarity","precision"],"placeholder":"I don't know yet and I'm not going to guess — samples went to the lab Monday and we'll have results Thursday."},
    {"id":"pressure-agri-mid-04","level":"mid","profession":"agriculture","title":"'Can you guarantee the volume?'","scenario":"The wholesale buyer asks on the call: 'Can you guarantee me full volume next season?' A flat yes is a lie — you farm outdoors. A shrug loses the contract. The honest answer commits to what you control and names what you don't.","task":"Write the 3-sentence answer that is honest without sounding weak.","tips":["Lead with what you can commit: acres planted, irrigation secured, history of delivery.","Name the honest limit in one clause — weather — without hiding behind it.","Offer the mechanism that protects them: early warning at set dates, a backup grower network."],"focus":["clarity","audience"],"placeholder":"I can guarantee the acres, the water, and that you'll never be surprised — we've delivered 95% or better four years running. What I can't control is weather, so here's what I do control: you get a firm volume forecast on the first of every month."},
    {"id":"pressure-agri-mid-05","level":"mid","profession":"agriculture","title":"'Whose fault was the drift?'","scenario":"Herbicide drifted onto the neighbor's beans and the owner asks in front of two crew members: 'Who screwed this up?' Naming the operator throws him under the bus; dodging looks like you can't run a crew.","task":"Write the 2-3 sentence answer that owns it at the right level without scapegoating.","tips":["Own it as the manager: the spray call was made under your system.","Describe the gap — no hard wind cutoff written down — not the person.","Individual accountability happens in private, later, and say so if pressed."],"focus":["clarity","impact"],"placeholder":"That's on me — we sprayed in wind I should have had a hard written cutoff for. I'm fixing the rule today, and anything about the operator I'll handle with him directly."},
    {"id":"pressure-agri-mid-06","level":"mid","profession":"agriculture","title":"The loaded drone question","scenario":"The owner, reviewing costs, asks: 'So you're telling me the drone was a five-thousand-dollar toy?' It found the tile blowout and the aphid pocket, but the question is framed to make any defense sound like excuse-making.","task":"Write the 2-3 sentence answer that reframes with facts, not protest.","tips":["Don't fight the word 'toy' — answer the real question: did it pay?","Two finds with dollar figures beat any adjective.","Reframe with arithmetic, calmly, and let the frame collapse on its own."],"focus":["clarity","precision"],"placeholder":"Fair question — here's the season's tally. It found the tile blowout in June, about $4,000 of drowned corn if we'd found it at harvest, and the aphid pocket we spot-sprayed for $300 instead of spraying the whole field for $2,100."},
    {"id":"pressure-agri-mid-07","level":"mid","profession":"agriculture","title":"The inspector finds the gap","scenario":"Mid-audit, the organic inspector points at the log: 'There's no entry for this field between June 3 and July 20. What happened here?' Something did happen — cultivation passes that nobody wrote down. Bluffing an inspector ends certifications.","task":"Write the 2-sentence answer that is straight about the gap and what you'll do, without volunteering a novel.","tips":["Answer exactly what was asked: the work happened, the entries didn't.","No embroidery — extra detail you can't back up creates new questions.","State the fix in one sentence: reconstructed from tractor logs today, new same-day rule going forward."],"focus":["clarity","precision"],"placeholder":"The cultivation passes happened — the entries didn't get made, and that's a process failure on my end. I can reconstruct dates from the tractor's GPS log today, and I've moved logging to same-day with the operator's initials."},
    {"id":"pressure-agri-mid-08","level":"mid","profession":"agriculture","title":"'Why didn't you sell at the top?'","scenario":"Canola touched $720 in July; you sold in September at $655. The owner slides the chart across the desk: 'Why didn't we sell at the top?' Hindsight is undefeated. Defensiveness loses; so does pretending you'd do the same again if you wouldn't.","task":"Write the 3-sentence answer: the decision as it looked then, the honest lesson, and the change.","tips":["Recreate the moment: at $720 the crop wasn't made yet — selling unmade crop is its own risk.","Concede what's real: we had no written target, and that's the fixable part.","End with the mechanism: standing orders at set prices this year."],"focus":["clarity","impact"],"placeholder":"In July the crop wasn't made — selling what you haven't grown is how farms get hurt worse than this. But the honest lesson is we had no written price target, so the decision drifted. This year we set standing sell orders in the spring."},
    {"id":"pressure-agri-mid-09","level":"mid","profession":"agriculture","title":"Challenged on deck","scenario":"Halfway through a thin trip, your senior deckhand says in front of the crew: 'We've been dragging dead water for two days — why are we not steaming north like the other boats?' It's half challenge, half fair question, and the whole deck is listening.","task":"Script the 2-3 sentence spoken answer that treats the question straight and keeps command of the deck.","tips":["Answer the substance — you have a reason; give it in plain terms.","No sarcasm, no pulling rank — the crew judges the answer, not the authority.","End with the decision point: what you're watching and when you'd move."],"focus":["clarity","audience"]},
    {"id":"pressure-agri-mid-10","level":"mid","profession":"agriculture","title":"The banker's dry-year question","scenario":"In the loan review the banker asks: 'What happens to your numbers if it doesn't rain this summer?' 'We'd manage' is not an answer a lender can file. She's testing whether you've done the arithmetic on the bad case.","task":"Write the 3-sentence answer: the bad-case number, the levers, and the floor.","tips":["Name the bad case in numbers: yields down 30%, revenue off about $180K.","List the levers in order: crop insurance covers the first tranche, then culling, then the feed contract exit.","End at the floor: worst case still services the loan — show the line."],"focus":["clarity","structure"],"placeholder":"A dry year like 2021 takes yields down about 30% — roughly $180K of revenue. Crop insurance covers the first $120K of that, and culling the bottom of the herd frees another $40K."},
    {"id":"pressure-agri-mid-11","level":"mid","profession":"agriculture","title":"'How bad is it — a number'","scenario":"After the July hailstorm the owner asks: 'How much did we just lose?' You've walked two of six fields. He wants a number now; a fake-precise one will be quoted back at you all year, and 'too early to say' sounds like hiding.","task":"Write the 2-sentence answer: an honest range from what you've seen, and when the real number arrives.","tips":["Give the range with its basis: 'from the two fields I've walked, 20 to 40 percent.'","Say what firms it up and when — the full walk by Thursday, adjuster Friday.","A bounded range with a date beats both a guess and a shrug."],"focus":["precision","clarity"],"placeholder":"From the two fields I've walked, we're somewhere between 20 and 40 percent — I'll have walked all six by Thursday and the adjuster confirms Friday."},
    {"id":"pressure-agri-mid-12","level":"mid","profession":"agriculture","title":"The neighbor at the gate","scenario":"Your neighbor is at the shop door, angry: 'Your spray burned the edge of my orchard — I want to know what you're going to do about it.' You don't know yet whether it was your application, his own, or frost. Admitting fault wrongly and stonewalling are both mistakes.","task":"Write the 3-sentence spoken response: take it seriously, commit to the facts, set the next step and time.","tips":["Take the concern seriously without conceding the cause: 'if my spray did that, I'll make it right.'","Commit to facts: your spray records, the wind log, walking the boundary together today.","Set the time: 'I'll be at your gate at four with the records.'"],"focus":["clarity","audience"],"placeholder":"If my spray did that, I'll make it right — full stop. Let me pull my spray records and the wind readings from that day, and I'll walk your boundary with you at four o'clock."},
    {"id":"pressure-agri-mid-13","level":"mid","profession":"agriculture","title":"The reporter's pesticide question","scenario":"At the fall fair, a local reporter asks on the record: 'Are you comfortable spraying chemicals so close to a school?' The question presumes the conclusion. Anger makes the story; jargon makes it worse. You have real practices worth describing.","task":"Write the 2-3 sentence quotable answer: honest, plain, and specific about what you actually do.","tips":["Answer the concern underneath: yes, and here's exactly what protects the school.","Specifics quote well: the buffer distance, the wind rule, the notification call.","Skip the industry talking points — one concrete practice beats them all."],"focus":["audience","clarity"],"placeholder":"I'd be uncomfortable too if it were done carelessly, so here's what we actually do: a 100-metre no-spray buffer on the school side, nothing above 10 km/h wind, and I call the principal's office before any application within sight of the yard."},
    {"id":"pressure-agri-mid-14","level":"mid","profession":"agriculture","title":"The AGM equipment grilling","scenario":"At the co-op AGM a member stands up: 'Why did we spend two hundred grand on a sprayer when custom operators are a phone call away?' You made that recommendation. The room includes members who agreed and members who didn't.","task":"Write the 3-sentence answer: the number that decided it, the risk it removed, and the honest break-even.","tips":["Lead with the decisive fact: custom couldn't come in the 72-hour windows that matter.","Give the arithmetic: cost per acre against custom rates, break-even in year four.","Concede the real trade-off — capital tied up — so the answer isn't a sales pitch."],"focus":["impact","clarity"],"placeholder":"Because in the two weeks a year when spraying is worth the most, custom operators were three to five days out — and fungicide doesn't wait. At our acres the machine breaks even against custom rates in year four."},
    {"id":"pressure-agri-mid-15","level":"mid","profession":"agriculture","title":"'Can we cut the crew and still finish?'","scenario":"The owner, staring at the payroll, asks: 'Could we finish harvest with two fewer on the crew?' The true answer is 'yes, but' — and the 'but' is the whole point: more days, more weather risk, and the overtime that eats half the savings.","task":"Write the 3-sentence answer that answers yes/no first, then prices the trade-off.","tips":["Direct answer first: 'We could — here's what it costs.'","Price the but: four more harvest days, and every added day is weather exposure.","Give him the real comparison: $6K saved against the odds of a $30K weather hit."],"focus":["clarity","precision"],"placeholder":"We could — with two fewer we finish, but it takes four more days. That saves about $6K in wages and puts 300 more acres at the mercy of an October forecast."},
    {"id":"pressure-agri-mid-16","level":"mid","profession":"agriculture","title":"The double-barreled question","scenario":"On the phone the owner fires two questions at once: 'Is the corn dry enough to start, and did the parts for the header show up?' Answering them tangled together — 'well, the parts thing is complicated' — muddies both.","task":"Write the answer that takes each question in turn, clearly labeled, one sentence each.","tips":["Split them out loud: 'Corn first — yes. Parts — no, and here's the plan.'","One sentence per answer before any elaboration.","Order by his priority, not by which answer you like better."],"focus":["structure","clarity"],"placeholder":"Corn first: yes, testing 15.2 this morning, we can start. Parts: no — the header parts slipped to Thursday, so we open with the east fields that don't need them."},
    {"id":"pressure-agri-mid-17","level":"mid","profession":"agriculture","title":"'Where are prices going?'","scenario":"The owner asks where wheat prices go from here. Nobody knows — not you, not the analysts he reads. Pretending to know sets you up; a bare 'no idea' abdicates. The strong answer separates what's unknowable from what you're doing about it.","task":"Write the 2-3 sentence answer: honest about the unknown, concrete about the plan.","tips":["Say the true thing first: 'I don't know, and neither does anyone selling forecasts.'","Pivot to what you control: the selling plan with its trigger prices.","Certainty about your process substitutes for certainty about the market."],"focus":["clarity","impact"],"placeholder":"I don't know — and I'd be careful of anyone who says they do. What I do know is our plan: we're 40% sold above break-even already, and standing orders take another 30% if it touches $9.20."},
    {"id":"pressure-agri-mid-18","level":"mid","profession":"agriculture","title":"Land it in ten seconds","scenario":"The board chair has interrupted your harvest update twice: 'Sorry — short version?' Whatever you say next is the update. Ten seconds, the verdict and the one number, or you've lost the room for good.","task":"Write the one-sentence version of a harvest update you'd normally give five minutes.","tips":["Verdict plus number: 'Harvest is 80% done, tracking 6% over budget, no open problems.'","If they want more, they'll ask — that's the system working.","Practice the ten-second version of everything you own; you'll need it monthly."],"focus":["concision","impact"],"placeholder":"Harvest is 80% done, yields tracking 6% over budget, and nothing needs a decision from this table."},
    {"id":"pressure-agri-mid-19","level":"mid","profession":"agriculture","title":"The bookkeeper's seed-bill challenge","scenario":"The owner's wife runs the books and calls with the seed invoice in hand: 'This is eleven thousand more than last year — did you order the wrong thing?' She's sharp, she's right about the number, and she signs the cheques.","task":"Write the 2-3 sentence answer that respects the challenge and accounts for the delta precisely.","tips":["Confirm her number first — arguing with the bookkeeper's arithmetic never ends well.","Break the delta into its parts: price per bag up 9%, plus the switch to treated seed on 300 acres.","End with what the treated seed buys — the replant insurance it replaces."],"focus":["clarity","precision"],"placeholder":"Your number's right — eleven-two higher. Two pieces: seed price itself rose 9%, about $6K, and I moved 300 acres to treated seed, about $5K, which replaces the replant risk that cost us $9K two years ago."},
    {"id":"pressure-agri-mid-20","level":"mid","profession":"agriculture","title":"'The neighbors finished last week'","scenario":"The owner drives past the neighbor's bare fields and calls: 'The Andersons finished a week ago — why are we still combining?' The comparison stings and it's incomplete: they grow 900 acres of one early crop; you grow 1,600 across four.","task":"Write the 2-sentence answer that adds the missing context without sounding defensive.","tips":["Give the like-for-like fact calmly — different acres, different crops, different finish line.","One comparison that lands: your wheat finished before theirs did.","No heat — a manager who sounds stung sounds behind."],"focus":["clarity","impact"],"placeholder":"The Andersons run 900 acres of early barley — one crop, one finish line. Our wheat was actually off before theirs; what's left is the corn, which nobody combines in September."},
    {"id":"pressure-agri-mid-21","level":"mid","profession":"agriculture","title":"The under-grade accusation","scenario":"The packer emails: 'Your last load graded 8% defects, double the spec — we're applying the penalty clause.' You inspected that load and it was clean when it left. You haven't seen their grading data, and firing back blind is a mistake either way.","task":"Write the 2-3 sentence reply that neither concedes nor fights, and sets up the verification.","tips":["Take it seriously without accepting it: 'that doesn't match my loading inspection — let's find out why.'","Ask for the specifics: grading sheet, photos, and whether the sample can be held.","Facts first, penalty conversation second — say so politely."],"focus":["clarity","precision"],"placeholder":"That doesn't match what I inspected at loading, so let's get to the bottom of it before we talk penalties — can you send the grading sheet and photos, and hold the sample for me to see?"},
    {"id":"pressure-agri-mid-22","level":"mid","profession":"agriculture","title":"'Why wasn't I called sooner?'","scenario":"The vet arrives to a cow that's been down for two days and asks flatly: 'Why am I only seeing her now?' The honest answer is you tried to manage it yourself to save the call fee, and it cost the cow. The vet's trust in your judgment is on the line.","task":"Write the 2-sentence spoken answer that owns it straight and resets the standard.","tips":["No excuses dressed as reasons — 'I tried to save a call fee and I was wrong.'","Reset the trigger: what will make you call on day one from now on.","Vets forgive mistakes owned; they never forget mistakes explained away."],"focus":["clarity","impact"]},
    {"id":"pressure-agri-mid-23","level":"mid","profession":"agriculture","title":"'So organic is just marketing?'","scenario":"At the farmers market a customer says, half-smiling: 'Come on — organic is just a sticker and a higher price, right?' Three other customers are in earshot. A lecture loses them; agreeing betrays your certification and your price.","task":"Write the 2-3 sentence answer that's warm, concrete, and quotable.","tips":["Meet the skepticism with a concrete practice, not a philosophy.","One vivid specific: what you do for weeds at 5 a.m. instead of what you'd spray.","Keep it warm — the audience is the people listening, not the skeptic."],"focus":["audience","impact"],"placeholder":"Fair — the sticker doesn't tell you much. Here's what it means on my farm: we control weeds with a cultivator and a crew at five in the morning instead of a $40 jug, and an inspector audits every field log once a year to keep me honest."},
    {"id":"pressure-agri-mid-24","level":"mid","profession":"agriculture","title":"'Are you sure it was hail?'","scenario":"The insurance adjuster, walking the beans, says: 'Some of this looks like disease to me, not hail. Are you sure about this claim?' Your answer decides whether the claim proceeds. You have evidence: dated photos and the storm's timing.","task":"Write the 2-3 sentence answer that answers with evidence and stays unrattled.","tips":["Composure is evidence too — adjusters read the farmer as much as the field.","Point to the timeline: clean scouting photos on the 12th, storm the 14th, damage pattern matching the storm track.","Invite the test that settles it: pull plants from the strip the storm missed."],"focus":["precision","clarity"],"placeholder":"I'm sure, and I can show you why: scouting photos from the 12th show clean plants, the storm hit the 14th, and the damage stops in a line right where the cell passed. Pull plants from the west strip it missed and compare."},
    {"id":"pressure-agri-mid-25","level":"mid","profession":"agriculture","title":"'Why do we always get the worst blocks?'","scenario":"In the morning huddle, a picker asks loudly: 'Why does our crew always get the thin blocks while Rosa's crew gets the heavy fruit?' It's about piece-rate money, the whole crew is listening, and the assignment history is more even than he thinks.","task":"Script the 2-3 sentence spoken answer that treats the money question as legitimate and answers it with facts.","tips":["Don't hear it as insubordination — piece-rate workers asking about earnings is fair.","Answer with the record: the rotation over the past two weeks, block by block if needed.","Commit to transparency going forward: the assignment board where everyone sees the rotation."],"focus":["audience","clarity"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-agri-mid-01","level":"mid","profession":"agriculture","title":"Before and after for the tile","scenario":"You're pitching drainage tile for the east quarter to the owner. Your draft is a contractor quote and a soil map. What persuades is the contrast: the quarter as it is every wet spring versus the quarter it could be, made concrete.","task":"Write a 3-4 sentence case that frames the before state, the change, and the after state.","tips":["Paint 'before' with the scene he knows: the planter parked at the field edge in May, waiting.","The tile is the turning point — one sentence.","Make 'after' concrete: planted with the rest of the farm, the 20% yield gap closed."],"focus":["impact","structure"],"placeholder":"Every wet May it's the same picture: the planter sitting at the edge of the east quarter while the rest of the farm is done."},
    {"id":"narrative-agri-mid-02","level":"mid","profession":"agriculture","title":"Make the PTO stakes real","scenario":"You're talking to the crew about shutting off the PTO before clearing plugged equipment. The rulebook version washes over them — they've heard it. What moves people is the concrete stake: what a driveline at 540 rpm actually does, and who waits at home.","task":"Script the 3-4 sentence spoken appeal that makes the stake real without being gratuitous.","tips":["Trade 'serious injury may result' for the physical truth — a sleeve caught at that speed wraps a man in under a second.","Real, not lurid — the truth is heavy enough.","Land it on them: your hands, your kids, the thirty seconds it takes to shut it down."],"focus":["impact","audience"]},
    {"id":"narrative-agri-mid-03","level":"mid","profession":"agriculture","title":"Pre-empt the probe objection","scenario":"You want four soil-moisture probes at $1,800 each, and you already know the owner's first line: 'Seven grand to be told the dirt is dry? I can kick it and tell you that.' The strongest pitch says his objection out loud before he does — then answers it.","task":"Write a 3-4 sentence pitch that names the cost objection first and dismantles it with the irrigation math.","tips":["Say it for him: 'Seven grand to measure what a shovel shows — I know how it sounds.'","Then the math: two irrigations skipped last year on gut feel that the probes would have confirmed, worth $5K in pumping.","An objection you raise yourself is half-answered already."],"focus":["impact","precision"],"placeholder":"Seven grand to measure what a shovel shows — I know exactly how that sounds. But last season we ran two irrigations the probes would have told us to skip."},
    {"id":"narrative-agri-mid-04","level":"mid","profession":"agriculture","title":"The packing-line change story","scenario":"You're rolling out a new pack-line procedure — quality checks moved upstream — and want the crew to buy in, not just comply. A list of steps gets compliance. The story of why the old way hurt them — whole pallets rejected at the end of a long day — gets buy-in.","task":"Write a 3-4 sentence narrative that frames the change around the pain they already know.","tips":["Start from the day they remember: the Thursday the buyer bounced three pallets and everyone re-packed until seven.","Show the change as the fix for that night, not a new demand.","End with what their day looks like after: catch it at the table, never re-pack a pallet."],"focus":["impact","audience"],"placeholder":"Remember the Thursday we re-packed three pallets until seven at night? That happened because we inspect at the end, when it's too late to fix anything cheap."},
    {"id":"narrative-agri-mid-05","level":"mid","profession":"agriculture","title":"'We tried cover crops in 2019'","scenario":"You're proposing cover crops again and the owner's answer is loaded before you start: 'We tried that in 2019 and mowed a mess into the mud.' Ignoring that history dooms the pitch. Naming it — and what's different — is the only way through.","task":"Write a 3-4 sentence pitch that raises the 2019 failure yourself and shows specifically what changed.","tips":["Open with the failure on your lips, not his: '2019 went badly, and I know why now.'","Name the specific differences: species mix, seeding date moved up three weeks, a termination plan with a date.","Honoring the history is what earns permission to try again."],"focus":["impact","structure"],"placeholder":"2019 went badly and I've figured out why: we seeded rye too late and had no termination plan. This time it's an oat-radish mix that winterkills — seeded by September 1, dead by December, no spring mess."},
    {"id":"narrative-agri-mid-06","level":"mid","profession":"agriculture","title":"The new net, in fuel","scenario":"You're the skipper asking the boat's owner for a $14,000 low-drag trawl. He hears 'new gear' as 'skipper wants toys.' The persuasive frame is the fuel story: what the old net costs every single tow, and when the new one pays it back.","task":"Write a 3-4 sentence case built on the before/after fuel math.","tips":["Before: 34 litres an hour dragging the old net, every tow, all season.","After, with the trial data from the boats that switched: 15% less drag, roughly $500 a trip.","Land at the payback date, not the price tag — it pays for itself by June."],"focus":["impact","precision"],"placeholder":"The old net costs us about $500 in extra fuel every trip against the low-drag gear the Kestrel switched to. At thirty trips a season, the $14,000 net pays for itself by June — after that it's straight savings."},
    {"id":"narrative-agri-mid-07","level":"mid","profession":"agriculture","title":"The renewal story","scenario":"The grocery buyer is deciding whether to renew your contract or consolidate with a bigger supplier. Your draft lists specs and prices — which the big supplier beats. Your actual advantage is a story: three years, zero shorted weeks, and the August heat wave when you were the only one who delivered.","task":"Write a 3-4 sentence renewal case that leads with the story the spec sheet can't tell.","tips":["Open with the heat wave: the week every other supplier shorted her and your truck showed up anyway.","Turn history into a promise: this is what the contract actually buys.","Concede the price gap and reframe it — the premium is the insurance she already collected on."],"focus":["impact","audience"],"placeholder":"In the August heat wave, when every supplier on your list shorted you, our truck was at your dock both Tuesdays — full."},
    {"id":"narrative-agri-mid-08","level":"mid","profession":"agriculture","title":"The dryer, before and after","scenario":"You're making the grain dryer case to the co-op board. Your draft leads with specs: bushels per hour, BTU ratings. What the board remembers is contrast: last October versus the October the dryer buys them.","task":"Write a 3-4 sentence before/after case for the board.","tips":["Before, vividly: last October, 40,000 bushels standing wet while three farms queued for one elevator dryer, and the snow that caught the last 5,000.","The dryer is the pivot — one sentence, one number.","After: harvest runs on your clock, wet years become schedule problems instead of crop losses."],"focus":["impact","structure"],"placeholder":"Last October we had 40,000 bushels standing wet in the field, queued behind three farms for the elevator's dryer — and snow took the last five thousand."},
    {"id":"narrative-agri-mid-09","level":"mid","profession":"agriculture","title":"The farm that lost its sticker","scenario":"Your crew leads still treat the organic field logs as paperwork. Rules haven't moved them. What might: the true story of the operation two counties over that lost certification over reconstructed logs — and what the three-year re-transition did to them.","task":"Write a 3-4 sentence telling of that story that lands the stake without a lecture.","tips":["Tell it as a story, not a warning label: a real farm, a routine audit, one log that didn't hold up.","The consequence in their terms: three years selling organic-grown crop at conventional prices.","One sentence to bring it home: our logs are that farm's logs, every day."],"focus":["impact","audience"],"placeholder":"Two counties over, a farm most of you would recognize lost its certification last year — not for spraying anything, but because their logs were reconstructed the week before the audit and the inspector could tell."},
    {"id":"narrative-agri-mid-10","level":"mid","profession":"agriculture","title":"The shared header pitch","scenario":"You want to split a $90,000 corn header with the neighbor — your harvests barely overlap. A cold proposal reads as 'lend me money.' The persuasive frame is mutual: what each side pays now for owning alone, and the payback both get.","task":"Write a 3-4 sentence pitch framed on the shared problem and mutual gain.","tips":["Open on the shared absurdity: two headers, each working three weeks a year, parked side by side for the other forty-nine.","Numbers for both sides: half the capital each, and the usage calendar that shows the overlap is four days.","Name the objection — the four overlap days — and offer the rule that settles it before he raises it."],"focus":["impact","audience"],"placeholder":"Between us we own $180,000 of corn headers that each work three weeks a year. Our harvest windows overlap four days on the calendar — and I'd give you first call on those days in writing."},
    {"id":"narrative-agri-mid-11","level":"mid","profession":"agriculture","title":"Ask the veteran to teach","scenario":"Your best operator is two seasons from retiring and none of his judgment is written down. You want him mentoring the two young operators, but 'training duties' sounds to him like being put out to pasture. The frame that works is legacy, not liability.","task":"Write what you'd say to him in 3-4 sentences, framed around what he leaves behind.","tips":["Lead with the truth that flatters because it's true: thirty years of judgment walks out the gate with him unless it walks into someone first.","Make it his call and his method — shadow seats, not classrooms.","Name the concrete first step: Marcus rides with him through spring planting."],"focus":["impact","audience"]},
    {"id":"narrative-agri-mid-12","level":"mid","profession":"agriculture","title":"The ten acres of Macs","scenario":"Ten acres of old McIntosh loses money most years, but the owner's father planted those trees and 'they still produce.' Your replant case needs numbers and a story that respects the sentiment instead of bulldozing it.","task":"Write a 3-4 sentence case that honors the history and still lands the change.","tips":["Acknowledge what the block means before what it costs — one sentence, sincere.","Then the arithmetic: $9K average annual loss, against Ambrosia's projected margin from year five.","Frame the replant as continuing the father's move, not erasing it — he planted the best variety of his day too."],"focus":["impact","audience"],"placeholder":"Your dad planted those Macs when they were the best apple anyone could grow — and that's exactly the standard I want to hold the block to now."},
    {"id":"narrative-agri-mid-13","level":"mid","profession":"agriculture","title":"Pre-empt 'but prices might rally'","scenario":"You're recommending forward-contracting a third of the new crop at today's profitable price. You know the owner's objection by heart: 'What if prices rally and we've sold cheap?' The pitch has to defuse that before it's spoken.","task":"Write a 3-4 sentence recommendation that names the rally objection and answers it with the downside math.","tips":["Say his line for him: 'if it rallies, this contract will look like money left on the table.'","Answer with asymmetry: a third sold still leaves two-thirds riding the rally — but a crash with nothing sold has no floor at all.","Anchor on the goal: locking cost of production, not calling the top."],"focus":["impact","precision"],"placeholder":"If prices rally, this contract will look like money left on the table — I want to say that before you do. But a third sold at a profit still leaves two-thirds riding any rally, while a crash with nothing sold has no floor."},
    {"id":"narrative-agri-mid-14","level":"mid","profession":"agriculture","title":"Water you can see","scenario":"Crew members keep leaving hand-line valves cracked open and gates half-set — each one 'just a trickle.' The allocation is 20% short this year. Abstract appeals about conservation haven't worked. Make the waste visible and the stake theirs.","task":"Write the 3-4 sentence huddle talk that makes the trickle concrete and ties it to their season.","tips":["Convert the trickle: one cracked valve overnight is a day of water for the tomato block.","Tie the allocation to their jobs — when the water runs out, the late crops and the late-season hours go with it.","End with the one habit: walk your line before you leave it."],"focus":["impact","clarity"],"placeholder":"One valve left cracked overnight runs about 30,000 litres — a full day of water for the tomato block, gone while we sleep."},
    {"id":"narrative-agri-mid-15","level":"mid","profession":"agriculture","title":"The wash-shed vote","scenario":"The co-op board votes next month on funding a shared wash-pack shed. Your spreadsheet is solid and has persuaded nobody. What might: the story of the Vermeulens, who lost their biggest wholesale account last year for want of a certified wash line.","task":"Write the 3-4 sentence version of that story that carries the vote, ending on the decision.","tips":["One family, one account, one reason — specifics persuade where categories don't.","Make the shed the counterfactual: with it, that account never leaves.","Land on the vote: every grower at this table is one buyer-audit away from the same call."],"focus":["impact","structure"],"placeholder":"Last spring the Vermeulens lost their biggest wholesale account — not on quality, not on price, but because the buyer's audit required a certified wash line and theirs was a garden hose and a folding table."},
    {"id":"narrative-agri-mid-16","level":"mid","profession":"agriculture","title":"The farm-stand pitch to a grain man","scenario":"You want to trial a farm stand and pick-your-own on the road frontage. The owner is a commodity grower to his boots: 'We farm, we don't run a petting zoo.' The persuasive frame is margin — what an acre earns wholesale versus retail — told through one nearby example.","task":"Write a 3-4 sentence pitch in his language: margin per acre, small trial, hard numbers.","tips":["Open inside his frame: same acre, three times the margin — then prove it.","Use the neighbor example: the Klassens' five roadside acres net more than forty wholesale ones.","Shrink the risk: a two-acre trial, one season, existing crew — the exit costs nothing."],"focus":["impact","audience"],"placeholder":"Same acre of strawberries: wholesale nets us about $4,000, and the Klassens clear over $12,000 retail at their stand. I'm asking for a two-acre trial, one season, staffed by the crew we already have."},
    {"id":"narrative-agri-mid-17","level":"mid","profession":"agriculture","title":"Sell the harvest log to the crew","scenario":"You're introducing bin-tag logging at harvest — every bin traced to block and picker. The crew hears surveillance. The story that lands is the one where the data works for them: the picker who proved her rate, and the bonus math that follows.","task":"Write a 3-4 sentence introduction that frames the logging around what it does for them.","tips":["Name the fear out loud — 'this isn't about watching you' rings hollow unless you say what it IS about.","The story: last year Reyna's crew swore they out-picked everyone and had no way to prove it — now they would.","End on the concrete: logged bins are how the quality bonus gets paid on evidence instead of memory."],"focus":["impact","audience"]},
    {"id":"narrative-agri-mid-18","level":"mid","profession":"agriculture","title":"The buffer strips argument","scenario":"The owner wants to log right to the creek on the new block — 'we own to the waterline.' You want the 30-metre buffers kept. The regulatory argument is real but abstract; the story of the operation that lost its certification and its market access is concrete.","task":"Write a 3-4 sentence case that pairs one hard consequence with one story that makes it real.","tips":["The hard fact first: a creek violation means fines and a stop-work — mid-contract, with trucks booked.","Then the story: the outfit upcoast that lost its sustainable certification and with it the mill contract that wanted certified wood.","Frame the buffer as cheap insurance: 4% of the block's volume against the whole contract."],"focus":["impact","clarity"],"placeholder":"Logging to the waterline risks a stop-work order mid-contract — but the bigger number is what happened to Coastal Ridge: one creek violation, certification pulled, and the mill contract that required certified wood went with it."},
    {"id":"narrative-agri-mid-19","level":"mid","profession":"agriculture","title":"The map that tells a story","scenario":"You're pitching variable-rate fertilizer to the owner with a yield map in hand. The map alone is wallpaper. The story in it — the farm has been feeding its best acres and starving its worst for a decade — is the pitch.","task":"Write the 3-4 sentence pitch that turns the map into a before/after story.","tips":["Name what the map says in one plain sentence: we fertilize every acre the same, and the acres are not the same.","Before: flat-rate spreading, over-feeding the sand hills that can't use it, under-feeding the loam that could.","After, with the number: same fertilizer bill, redistributed — trial farms show 4-7 bushels where it counts."],"focus":["impact","structure"],"placeholder":"This map says one thing: we've spent ten years feeding every acre the same when the acres aren't the same — over-feeding sand that can't hold it, starving loam that could do more."},
    {"id":"narrative-agri-mid-20","level":"mid","profession":"agriculture","title":"The lender hears a track record","scenario":"You're presenting the expansion loan — 300 more acres — to the lender with the owner. The numbers are in the application. What the application can't say is the arc: three years ago this farm missed payments; the last eight quarters it hasn't missed once. That story is the real collateral.","task":"Write the 3-4 sentence narrative opening for the meeting, before the numbers.","tips":["Own the low point first — the lender already knows it; naming it takes its power away.","The turn: what changed — cost tracking, forward selling, the discipline that made eight clean quarters.","Frame the expansion as the same discipline at larger scale, not a new bet."],"focus":["impact","audience"],"placeholder":"Three years ago this file had missed payments in it, and I won't pretend otherwise. What changed is the operating discipline — and the last eight quarters, every payment on time, are what that discipline looks like."},
    {"id":"narrative-agri-mid-21","level":"mid","profession":"agriculture","title":"Pre-empt 'too complicated for us'","scenario":"You're proposing section-control on the sprayer and you can hear the owner already: 'More screens, more subscriptions, more things only you know how to run.' It's his strongest card. Play it for him, then beat it.","task":"Write a 3-4 sentence pitch that names the complexity objection first and answers it concretely.","tips":["Voice it fully — a strawman version persuades no one: 'another screen, another subscription, another thing that breaks in week one of seasoning.'","Answer with specifics: one-day setup, the dealer's first-season support visit, and the neighbor's operator who learned it in an afternoon.","Then the payoff number: 8% overlap on our point rows, about $4,200 of double-sprayed product a year."],"focus":["impact","precision"],"placeholder":"I know the objection — another screen, another subscription, another gadget that breaks the first week we need it. So here's what convinced me: Hendersons' operator learned it in an afternoon, and it ends the 8% overlap that costs us about $4,200 in double-sprayed product every year."},
    {"id":"narrative-agri-mid-22","level":"mid","profession":"agriculture","title":"The robot and the 4 a.m. alarm","scenario":"You're pitching robotic milkers to a dairy owner who milks like his father did. Specs bounce off him. The before/after that lands is human: the 4 a.m. alarm he's answered for thirty years, the relief milker he can't hire, and what the herd data does for his breeding decisions.","task":"Write a 3-4 sentence pitch framed on his mornings and his herd, not the machine.","tips":["Before: the alarm, the unfindable relief milkers, the vacation he hasn't taken since 2019.","The robot is the pivot — one sentence, no spec sheet.","After: cows milked on their own schedule, and the udder-health data catching mastitis two days before any eye would."],"focus":["impact","audience"]},
    {"id":"narrative-agri-mid-23","level":"mid","profession":"agriculture","title":"One customer, one carrot","scenario":"You're proposing a CSA program to the farm's owners. The spreadsheet shows the deposit cash flow; it hasn't moved them. What might: one true story from the winter farmers market — the customer who drove forty minutes for your carrots and asked how to get them year-round.","task":"Write the 3-4 sentence pitch that opens with the customer story and lands on the cash-flow point.","tips":["Tell her story in two sentences — the drive, the question, the price she didn't blink at.","She is a category: forty families like her is a CSA, and you've met them all at the stand.","Land the finance point last: 120 deposits in March is planting money you don't borrow."],"focus":["impact","structure"],"placeholder":"A woman at the winter market drove forty minutes for our carrots and asked how she could get them year-round — and she didn't blink at the price."},
    {"id":"narrative-agri-mid-24","level":"mid","profession":"agriculture","title":"The quality bonus, sold to the deck","scenario":"You're changing the crew share: a slice of the catch value now rides on handling quality — bled, iced, stowed right. The deck will hear 'pay cut with extra steps.' The persuasive math is the price ladder: what the buyer pays for top-grade fish versus what rough handling has been costing every share.","task":"Write the 3-4 sentence deck talk that sells the change on their own arithmetic.","tips":["Open with the ladder: top-grade brings $2.10, rough-handled the same fish brings $1.40 — same ocean, same work, different care.","Show last trip's math: proper handling would have added roughly $900 per share.","Be straight about the risk: sloppy trips will pay less than before — that's the point, and the good hands profit from it."],"focus":["impact","precision"],"placeholder":"Same fish, same ocean: bled and iced right it sells at $2.10, thrown in the hold it sells at $1.40. On last trip's numbers, that difference was about $900 a share."},
    {"id":"narrative-agri-mid-25","level":"mid","profession":"agriculture","title":"The succession conversation","scenario":"The owner is 71, there's no written succession plan, and every lender meeting gets harder because of it. You need to persuade him to start the planning — a conversation every advisor has bounced off. The frame that fails is his age; the frame that might work is the farm's continuity.","task":"Write the 3-4 sentence opening that makes the stakes concrete without making it about his mortality.","tips":["Frame it around the farm, not the man: what happens to the crew, the contracts, and the land the year nothing is written down.","One concrete stake: the operating loan renews annually on his signature alone — a plan is what keeps the farm bankable.","Position planning as control, not surrender: the plan is how what he built keeps running his way."],"focus":["impact","audience"],"placeholder":"I want to talk about the farm's continuity — not because anything's wrong, but because right now every contract, the operating loan, and nine people's jobs sit on one signature."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-agri-mid-01","level":"mid","profession":"agriculture","title":"Short the buyer, headline first","scenario":"Blight took a third of the tomatoes and you'll fill 60% of next month's wholesale orders. Your draft email to the buyer spends two paragraphs on the weather before the number appears. She needs the shortfall in the first line to work her other suppliers in time.","task":"Write a 2-3 sentence message that front-loads the shortfall, then the plan.","tips":["Lead with the number and the dates — that's what she acts on.","Cause gets one clause, not a paragraph.","End with what you're doing for her: priority on your best grades, weekly volume updates."],"focus":["clarity","impact"],"placeholder":"We'll be at about 60% of contracted volume through August — blight took a third of the crop."},
    {"id":"hard-agri-mid-02","level":"mid","profession":"agriculture","title":"The clean no to harvest leave","scenario":"Your loader operator asks for four days off during peak harvest for a hunting trip booked months ago. You can't cover him and the answer is no. Your draft is a swamp of maybes — 'let me see, it's tricky, we'll figure something out' — that leaves him planning the trip.","task":"Write the 2-3 sentence answer that says no clearly, with the reason and what you can offer.","tips":["Say no plainly — a soft no that sounds like maybe is crueler when it lands later.","The honest reason: no second loader operator, and harvest doesn't move.","Offer what's real: first week after harvest wraps, guaranteed — don't dangle what isn't."],"focus":["clarity","impact"],"placeholder":"I can't give you those four days — you're the only loader operator I have and harvest can't hold. The first week after we wrap, you've got guaranteed, in writing."},
    {"id":"hard-agri-mid-03","level":"mid","profession":"agriculture","title":"Behavior, impact, ask on the greasing","scenario":"Your newest operator has skipped the daily greasing on the baler twice; the second time a dry bearing started smoking. You like the kid and your instinct is either a vague 'be more careful' or an explosion. The clean form is behavior, impact, ask.","task":"Write the 3-4 sentence feedback using behavior, impact, ask.","tips":["Name the behavior, dated and specific — not 'you're careless.'","The impact concrete: a $700 bearing, a half-day down, and a near fire.","End with the ask and the check: grease log initialed before the machine starts, and you'll check for two weeks."],"focus":["clarity","structure"],"placeholder":"The baler missed its greasing Tuesday and Friday — Friday the pickup bearing was smoking by noon. That was a $700 part, half a day of down time, and closer to a fire than I ever want to get."},
    {"id":"hard-agri-mid-04","level":"mid","profession":"agriculture","title":"Two crew spots won't return","scenario":"The owner cut the budget and two of your six seasonal workers won't be asked back next season. They're good workers; the decision is about money, not them. Your draft buries the news under paragraphs of praise and process.","task":"Write the 3-4 sentence message that delivers the news directly and humanely.","tips":["The news up front — hiding it in praise makes the praise feel like a trick.","Be honest about the reason: acreage and budget, not performance — and say so explicitly.","Give them what helps: dates, the reference letter you'll write, first call if a spot opens."],"focus":["clarity","impact"],"placeholder":"I have hard news: we're running four seasonal spots next year instead of six, and I can't offer you one. This is a budget decision — your work was never the problem, and my reference letter will say exactly that."},
    {"id":"hard-agri-mid-05","level":"mid","profession":"agriculture","title":"Tell the owner the canola is gone","scenario":"The reseeded canola failed too — flea beetles finished what the frost started. Four hundred acres will produce essentially nothing this year. The owner is at his daughter's wedding out of province, and this can't wait for his return. Your text keeps trying to soften itself into uselessness.","task":"Write the 3-sentence message that delivers the loss plainly, sizes it, and holds the next step.","tips":["Say it whole: the reseed failed, the field is done for the year.","Size it in his terms: roughly $190K of expected revenue, of which insurance covers about $120K.","Hold the next step so he doesn't have to think: claim filed, adjuster booked, options memo when he's back."],"focus":["clarity","impact"],"placeholder":"Bad news and I won't dress it up: the canola reseed failed — flea beetles — and the 400 acres are done for this year."},
    {"id":"hard-agri-mid-06","level":"mid","profession":"agriculture","title":"The termination opener","scenario":"After two written warnings, your equipment operator ran the sprayer again with the guard off — third time. You're letting him go this morning. The kindest version of this conversation is the clearest one: no ambush of small talk, no fog of maybes.","task":"Script the first three sentences of the conversation: the decision, the reason, and what happens next.","tips":["The decision in sentence one — 'this is your last day' — not after five minutes of warm-up.","The reason is the record: third guard violation after two written warnings; no new debate.","Then the logistics he needs: final pay, returning gear, the ride home if he needs one."],"focus":["clarity","impact"]},
    {"id":"hard-agri-mid-07","level":"mid","profession":"agriculture","title":"The dryer is over budget","scenario":"The grain dryer project you championed to the board is running $18,000 over the $85,000 approved — a foundation surprise and a power upgrade nobody quoted. The next board meeting is Tuesday. Bad budget news ages terribly; it must come from you, first, with the full number.","task":"Write the 3-4 sentence board message: the overrun, the causes, and your ask.","tips":["Lead with the full number — a partial confession now means a second confession later.","Two causes, one sentence each, no adjectives doing the apologizing.","End with the ask and the offset you found: approve the $18K, minus the $6K you cut elsewhere."],"focus":["clarity","structure"],"placeholder":"The dryer project is $18,000 over the approved $85,000, and I want this table to hear it from me with the full number. Two causes: the pad needed engineered footings the quote missed, and the power service upgrade came in double."},
    {"id":"hard-agri-mid-08","level":"mid","profession":"agriculture","title":"The fence fails spec","scenario":"The contractor finished the four kilometres of perimeter fence and it's wrong: posts at 5-metre spacing instead of the contracted 4, and the wire tension won't hold a motivated steer. He's a local guy you'll work with again. The redo conversation has to be clear without being scorched earth.","task":"Write the 2-3 sentence message that states the failure against the contract and the required fix.","tips":["Point to the contract, not your feelings: 4-metre spacing, clause and number.","Say the standard, not an insult: 'this won't hold cattle' is a fact about fence, not about him.","The ask is specific: re-set to spec before the herd moves in on the 15th, at his cost per the contract."],"focus":["clarity","precision"],"placeholder":"The fence isn't to contract — posts are at 5-metre spacing where we specified 4, and the tension won't hold cattle. I need it brought to spec before the herd moves onto that pasture on the 15th."},
    {"id":"hard-agri-mid-09","level":"mid","profession":"agriculture","title":"No bonus this year","scenario":"The crew has heard harvest-bonus talk all season, and after the hail and the market drop there's no money for it. They find out either from you, straight, or from the rumor mill, warped. You're telling them at the morning huddle.","task":"Script the 3-4 sentence announcement: the news, the honest reason, and what stands instead.","tips":["Say it in the first sentence — they'll know from your face anyway.","The reason with a number: the hail claim gap and where the season actually landed.","What stands: jobs are safe, wages unchanged, and the bonus structure returns next season in writing."],"focus":["clarity","audience"]},
    {"id":"hard-agri-mid-10","level":"mid","profession":"agriculture","title":"Leaving the vet practice","scenario":"After fifteen years, you're moving the herd work to the new practice with the on-call rotation your calving season needs. Dr. Halvorsen has been to this farm at 3 a.m. more times than you can count. He deserves to hear it from you, directly, before his office sees the records request.","task":"Write the 3-4 sentence message: the decision, the real reason, and what his years meant.","tips":["The decision first, unhedged — 'we're moving our herd work' — not a slow reveal.","The real reason, which is about coverage, not him: one vet can't be on-call 365 nights, and calving doesn't schedule.","Gratitude that's specific: the 3 a.m. prolapse in the ice storm — name one night that mattered."],"focus":["clarity","audience"],"placeholder":"I want you to hear this from me before the paperwork arrives: we're moving our herd work to the Riverbend practice, for their three-vet on-call rotation — a coverage decision, not a quality one."},
    {"id":"hard-agri-mid-11","level":"mid","profession":"agriculture","title":"The winch shortcut","scenario":"Your best deckhand has started riding the winch drum with his boot to guide the wire — saves thirty seconds a tow, and it's how men lose feet. He's skilled, senior, and the young crew copy everything he does. This conversation is behavior, impact, ask — on a moving deck.","task":"Script the 3-sentence talking-to using behavior, impact, ask.","tips":["The behavior, exactly: boot on the drum, last three tows — no 'attitude' talk.","The impact is double: his foot, and the two green hands who now think that's how it's done.","The ask is absolute, and lands on his seniority: the crew does what you do, so do it right."],"focus":["clarity","structure"]},
    {"id":"hard-agri-mid-12","level":"mid","profession":"agriculture","title":"No to the neighbor's combine ask","scenario":"Mid-harvest, your neighbor calls: his combine dropped a transmission and he wants to rent yours for three days. You have 600 acres standing and the forecast is unsettled. The answer is no — and he's the neighbor who lent you his grain cart in June.","task":"Write the 2-3 sentence answer: the no, the honest reason, and what you can actually offer.","tips":["The no early and unambiguous — a stalled maybe wastes the days he needs for finding another machine.","The reason is arithmetic he'll respect: 600 acres standing and one machine.","The real offer: your combine and your operator for the weekend after your wheat is off, if he's still stuck."],"focus":["clarity","impact"],"placeholder":"I can't do it, Pete — I've got 600 acres standing and one machine, and this forecast has me running scared. What I can offer: if you're still stuck when my wheat's off, you get the combine and my operator that weekend."},
    {"id":"hard-agri-mid-13","level":"mid","profession":"agriculture","title":"The well test came back bad","scenario":"The annual water test on the main barn well came back with coliform counts over the line. The herd is fine on the backup supply for now, but fixing it right — new casing seal, possibly a new well — is a $15-40K conversation the owner isn't expecting.","task":"Write the 3-4 sentence message: the result, what's protected already, and the decision ahead.","tips":["The result plainly, with the number and the line it crossed.","Immediately: what's already safe — herd switched to the backup line this morning, retesting scheduled.","Frame the decision with the range and the fork: seal repair at $15K if the casing holds, new well at $40K if not — driller assesses Thursday."],"focus":["clarity","structure"],"placeholder":"The barn well failed its water test — coliform over the safe line. The herd's been on the backup supply since this morning, so nothing's at risk today."},
    {"id":"hard-agri-mid-14","level":"mid","profession":"agriculture","title":"Stepping Dave back","scenario":"You promoted Dave to crew lead in the spring and it hasn't worked — assignments late, two good pickers quit his crew, and he's miserable in the job. You're moving him back to equipment operator, where he was the best you had. He'll hear 'demotion' no matter what you call it, so don't call it anything else.","task":"Write the 3-4 sentence conversation opener: the decision, the specific reasons, and what's true about his value.","tips":["The decision first, named honestly — dressing it as 'restructuring' insults you both.","Two specifics, not a character verdict: the schedule misses and the crew turnover.","What's true and useful: he's the best operator on the farm, at the same wage — that's the job you need him in."],"focus":["clarity","impact"]},
    {"id":"hard-agri-mid-15","level":"mid","profession":"agriculture","title":"Cancel the U-pick weekend","scenario":"A water test on the wash station came back questionable Friday morning, and the U-pick weekend you've advertised for a month — hundreds of families — has to be cancelled while you retest. The social post has to be clear, honest without inciting panic, and written in the next hour.","task":"Write the 2-3 sentence public post: the cancellation, the straight reason, and what happens next.","tips":["Cancel first, plainly — burying it under cheer reads as hiding something.","The reason honest but proportionate: a precautionary retest, nobody harmed, out of caution.","Give them the path: reopening date pending results, and honor this weekend's tickets next weekend."],"focus":["clarity","audience"],"placeholder":"We're cancelling this weekend's U-pick — a routine water test at our wash station came back unclear, and we won't open until a retest confirms everything is safe."},
    {"id":"hard-agri-mid-16","level":"mid","profession":"agriculture","title":"A member's load got rejected","scenario":"You manage the co-op elevator and a longtime member's canola delivery tested over the blackleg threshold — the whole load rejected, and his next deliveries need a clean test first. He's a board member's brother and he will be furious. The call has to be made this afternoon.","task":"Write the 3-sentence call opener: the result, what it means for him, and his path back.","tips":["Result first, with the number — the test is the message, not your judgment.","The consequence stated evenly: load refused, next deliveries need a clean sample first — same rule for every member.","The path back concrete: where to get the test, how fast, and his product isn't condemned — just this channel."],"focus":["audience","clarity"]},
    {"id":"hard-agri-mid-17","level":"mid","profession":"agriculture","title":"Terms are changing","scenario":"The restaurant group is 74 days behind on a 30-day account, third season running. You're moving them to payment-on-delivery — and you'd rather keep them as a customer than win an argument. The email needs to be unmovable on the terms and warm on the relationship.","task":"Write the 3-sentence email: the change, the factual reason, and the door left open.","tips":["The change first, dated: payment on delivery starting with next week's order.","The reason is the ledger, stated without heat: 74 days on 30-day terms.","Keep the door open concretely: six clean months on delivery terms and the account terms come back."],"focus":["clarity","impact"],"placeholder":"Starting with next week's delivery, your account moves to payment on delivery. The current invoice is 74 days past our 30-day terms — the third season we've been here — and I'd rather change the terms than the relationship."},
    {"id":"hard-agri-mid-18","level":"mid","profession":"agriculture","title":"Clubroot is on the farm","scenario":"The lab confirmed it: the patch in field 12 is clubroot. This isn't a one-season problem — it's a decade of rotation changes, equipment washing, and a quarter that can't grow canola for years. The owner needs the diagnosis, the horizon, and the plan in one message that doesn't flinch or catastrophize.","task":"Write the 3-4 sentence message: the confirmation, what it means long-term, and the immediate containment.","tips":["Name the disease and the certainty — 'lab-confirmed' ends the maybe phase.","The honest horizon in one sentence: field 12 is out of canola for at least four years; the fight now is keeping it to field 12.","Containment already moving: equipment wash protocol from today, that quarter worked last, resistant varieties for the neighbors' sake."],"focus":["clarity","precision"],"placeholder":"The lab confirmed clubroot in field 12. That quarter is out of canola for at least four years — the real fight now is keeping it out of the other fields."},
    {"id":"hard-agri-mid-19","level":"mid","profession":"agriculture","title":"Feedback for the agronomist","scenario":"Your agronomist called the fungicide pass unnecessary in June; the July scouting found the sclerotinia that cost maybe fifteen bushels an acre across two fields. You're not firing him — his other calls have paid for his fee many times. But this needs saying, specifically, before next season's plan.","task":"Write the 3-4 sentence message: the specific call, the cost, and what changes in how close calls get made.","tips":["The specific call and date, not a general gripe about advice.","The cost counted evenly: roughly 15 bu/ac over 300 acres — and say you know hindsight is cheap.","The change is process, not blame: on threshold calls, you want the odds and the downside, and the farm makes the risk decision."],"focus":["clarity","structure"],"placeholder":"I want to close the loop on the June sclerotinia call — the 'skip it' on fields 8 and 9 cost us around 15 bu/ac, about $40K. I know hindsight is cheap, and your calls have paid for your fee ten times over."},
    {"id":"hard-agri-mid-20","level":"mid","profession":"agriculture","title":"The housing move nobody wants","scenario":"The bunkhouse failed its electrical inspection and eight workers move to the motel in town for three weeks — twenty minutes from the fields, no kitchens, and none of them asked for this. The notice has to deliver an unpopular change with straight reasons and real compensations, in plain English.","task":"Write the 3-4 sentence notice for the crew: the move, the reason, and what you're doing to offset it.","tips":["The move and dates first — rumors are already ahead of you.","The reason honestly: the inspection failed and the rewiring isn't optional or fast.","The offsets concrete: van runs at 6 and 6, meal allowance per day, and the move-back date they can hold you to."],"focus":["clarity","audience"],"placeholder":"Starting Monday, everyone in the bunkhouse moves to the Parkway Motel for about three weeks — the electrical inspection failed and the rewiring can't happen with people living there."},
    {"id":"hard-agri-mid-21","level":"mid","profession":"agriculture","title":"Calling the trip early","scenario":"Six days into a planned ten-day trip, the hydraulics are limping and the forecast is closing. You're calling it — heading in tomorrow with two-thirds of a trip in the hold, and shares will show it. The crew deserves the call and the math from you on deck, not discovered at the dock.","task":"Script the 3-sentence deck announcement: the decision, the reasons, and the straight share math.","tips":["Decision first: we're heading in tomorrow at first light.","Both reasons, one sentence — the hydraulics you won't bet on and the weather window that's closing.","The money straight: shares land around two-thirds of a full trip — say the number range, don't let them do scared math all night."],"focus":["clarity","audience"]},
    {"id":"hard-agri-mid-22","level":"mid","profession":"agriculture","title":"Telling the owner you're leaving","scenario":"After nine seasons managing this farm, you've accepted the manager job at the bigger operation across the valley. The owner taught you half of what you know. He gets the news face to face, first, with a transition offer that honors what he gave you — but the decision itself is not up for negotiation.","task":"Write the 3-4 sentence opener: the decision, the timing, and the transition you're offering.","tips":["The decision stated as decided — 'I've accepted' — because reopening it helps neither of you.","Timing that protects him: you're here through harvest and the fall workplan.","The transition concrete: a written handover book, and you'll help interview your replacement if he wants."],"focus":["clarity","impact"],"placeholder":"I've accepted the manager position at Crestline, starting in November — I wanted you to hear it from me today, face to face. I'm here through harvest and the fall workplan, and my handover book will have everything in it."},
    {"id":"hard-agri-mid-23","level":"mid","profession":"agriculture","title":"Refusing the unsafe ask","scenario":"The owner, watching the forecast, tells you to send two workers into the grain bin tonight to break the crusted corn loose — no rescue equipment on site, no trained attendant. Bin entrapments kill people in this county every few years. Saying no to the man who signs your cheque is the job right now.","task":"Write the 2-3 sentence refusal: the no, the reason, and the alternative you'll execute instead.","tips":["The no unmistakable — softening it into 'I'd rather not' invites the push.","One reason, the real one: crusted corn over a void is how workers die, and you won't send anyone in without rescue gear and an attendant.","The alternative immediately: the bin whip contractor tomorrow morning, and what the delay actually costs against what it protects."],"focus":["impact","clarity"],"placeholder":"I won't send anyone into that bin tonight — crusted corn over a void is exactly how entrapments happen, and we have no rescue gear or attendant. The bin-whip contractor can be here at seven tomorrow for about $1,200."},
    {"id":"hard-agri-mid-24","level":"mid","profession":"agriculture","title":"The price-increase sign","scenario":"Feed, fuel, and wages are up, and the farm stand's egg and vegetable prices rise 15% next week — the first increase in three years. Your customers are neighbors. The sign has to say it straight, without a paragraph of apology and without corporate 'due to market conditions' fog.","task":"Write the 2-sentence sign: the change and the plain reason.","tips":["The change first and specific: new prices next Monday, about 15% up.","The reason in farmer words: feed and fuel, not 'market conditions.'","No over-apologizing — neighbors respect straight talk about costs; groveling invites doubt."],"focus":["audience","concision"],"placeholder":"Starting Monday our prices go up about 15% — the first increase in three years. Feed, fuel, and wages all cost more, and we'd rather charge fairly than cut corners."},
    {"id":"hard-agri-mid-25","level":"mid","profession":"agriculture","title":"The cull recommendation","scenario":"Twelve cows in the owner's herd are costing more than they produce — chronic high counts, poor breeding, two lame beyond fixing. One of them is Clover, the cow his kids halter-broke for the fair. The cull list conversation mixes arithmetic with sentiment, and pretending it's only arithmetic will lose it.","task":"Write the 3-4 sentence recommendation: the list, the numbers, and the honest acknowledgment of the hard one.","tips":["The recommendation whole: twelve cows on the cull list, with the per-head loss figure.","The arithmetic clean: what they cost monthly against the replacement heifers ready to enter.","Name Clover yourself — one sentence that respects it — and let him make that single call separately."],"focus":["clarity","audience"],"placeholder":"I'm recommending twelve cows for the cull list — together they're losing about $2,100 a month against what replacement heifers would produce. Eleven of them are straightforward. The twelfth is Clover, and I'd understand if that one's your call, not mine."}
  ],
  "putting-it-together": [
    {"id":"together-agri-mid-01","level":"mid","profession":"agriculture","title":"The combine fire escalation","scenario":"The older combine caught fire in the field an hour ago — crew safe, machine likely totaled, 400 acres still standing and rain forecast in five days. Your message to the owner needs the point up front, precise facts, and a recommendation — all readable in the cab of his truck in twenty seconds.","task":"Write the 3-4 sentence escalation: safety first, the facts, and your recommended move.","tips":["Lead with people: everyone is safe — that's always sentence one.","Facts precise: machine status, acres standing, the weather clock.","End owning the move: the custom harvester on the phone, price and start date, needing his yes."],"focus":["structure","impact"],"placeholder":"Everyone's safe — the 9600 caught fire in the south quarter about an hour ago and it's likely a write-off. We've got 400 acres standing and rain forecast Friday."},
    {"id":"together-agri-mid-02","level":"mid","profession":"agriculture","title":"Same news, two channels","scenario":"Harvest starts Thursday at dawn. The crew lead needs a text tonight; the co-op board needs a note in tomorrow's packet. Same fact, two completely different messages — one is logistics, the other is confidence and context.","task":"Write both: the one-line text to the crew lead and the 2-3 sentence note for the board packet.","tips":["The text is pure operations: start time, field, who hauls.","The board note carries the frame: on schedule, moisture at target, and what the season looks like from here.","Register is a choice — make each message sound like its channel."],"focus":["audience","concision"],"placeholder":"Text: Harvest starts Thursday 6 a.m., west wheat first — Miguel hauls, I'm on the combine. Board note: Wheat harvest begins Thursday, on schedule, with moisture at target."},
    {"id":"together-agri-mid-03","level":"mid","profession":"agriculture","title":"Edit the weekly like a reader","scenario":"Your Friday report to the owner has grown to 500 words: weather recap, day-by-day activity, three machine notes, and — buried in paragraph four — the fact that the potato crop is trending 12% over budget and the buyer wants to talk volume. Read it as he does, on a phone, in a truck.","task":"Rewrite the report's opening 2-3 sentences so the lead is on top and the rest can be skimmed or skipped.","tips":["First question: what does he need in the first ten seconds? The 12% and the buyer call.","Cut what's true every week — weather recaps and routine passes earn no lines.","Structure the rest as three skimmable bullets, not a diary."],"focus":["structure","concision"],"placeholder":"Potatoes are trending 12% over budget, and the buyer wants a volume call next week — that's the headline. Everything else this week was routine."},
    {"id":"together-agri-mid-04","level":"mid","profession":"agriculture","title":"The readiness verdict","scenario":"Spring board meeting, and the question on every face: is the operation ready for planting? You have five minutes and everything you've practiced — verdict first, evidence, the one open risk, and a recommendation — has to show up in the same short brief.","task":"Write the 4-5 sentence brief: verdict, evidence, the risk, and your recommended action on it.","tips":["Open with the verdict: ready, with one exception.","Evidence earns the verdict — seed on farm, machines through pre-season service, crew hired.","Name the one risk honestly and recommend the action that closes it, with a date."],"focus":["structure","impact"],"placeholder":"We're ready for planting on every front but one. Seed is on farm, both tractors are through service, and the crew is hired and starts Monday."},
    {"id":"together-agri-mid-05","level":"mid","profession":"agriculture","title":"Three crews, one harvest plan","scenario":"Cherry harvest starts Monday across three blocks with three crews — one yours, two from the labor contractor. Your kickoff message has to lead with the plan, give each crew its exact block, start and quota, and pre-empt the argument you know is coming about who gets the heavy-fruit block.","task":"Write the 4-5 sentence message: the plan up front, each crew's specifics, and the rotation rule that pre-empts the fairness fight.","tips":["Lead with the shared plan and the finish line: three blocks, ten days, all in before the heat.","Each crew gets its numbers — block, start time, daily bin target — precision prevents disputes.","Name the objection before it's raised: blocks rotate every three days, posted on the board."],"focus":["structure","precision"],"placeholder":"Cherry harvest starts Monday: three crews, three blocks, all fruit in within ten days. Crew A opens on the river block at 6, target 90 bins a day."},
    {"id":"together-agri-mid-06","level":"mid","profession":"agriculture","title":"The price-hold email","scenario":"Your carrot contract renews next month and the processor's opening letter proposes a 6% price cut, citing 'market conditions.' Your reply needs the ask up front, a case built on your delivery record and their alternatives' real costs, and their strongest argument pre-empted — all in an email that stays warm enough to keep the relationship.","task":"Write the 4-5 sentence reply: the ask, the record, the comparison, and the pre-empted objection.","tips":["Lead with the ask: renew at current price.","The case is your record: five years, 98% of contracted volume delivered, zero rejected loads.","Pre-empt their card — cheaper suppliers exist — with what those suppliers cost them in shorted weeks and trucking distance."],"focus":["impact","precision"],"placeholder":"I'm asking to renew at the current price, and here's the case. In five years we've delivered 98% of contracted volume with zero rejected loads."},
    {"id":"together-agri-mid-07","level":"mid","profession":"agriculture","title":"The harvest kickoff talk","scenario":"Tomorrow the whole operation pivots to harvest — long days, new hires mixed with veterans, machinery everywhere. Your kickoff talk at tonight's crew meal needs one governing message they'll still remember in week three, said in the crew's language, with a close that sounds like a leader and not a memo.","task":"Script the 4-5 sentence talk: the one message, the plain-language stakes, and the close.","tips":["Pick the one message — 'nobody gets hurt getting this crop in' — and open with it.","Everything else hangs off that message; don't add a second theme.","Close with presence: restate it, and tell them what you'll be doing to hold it."],"focus":["audience","impact"]},
    {"id":"together-agri-mid-08","level":"mid","profession":"agriculture","title":"The claim letter that gets paid","scenario":"The hail claim goes to the insurer this week. The letter has to work like everything you've practiced at once: the claim stated up front, the damage in counted numbers, the evidence organized so an adjuster can verify it fast, and the specific ask with a date.","task":"Write the 4-sentence core of the letter: claim, quantified damage, evidence available, and the ask.","tips":["Lead with the claim: policy number, crop, acres, event date.","Damage in counts, not adjectives: strikes per hundred fruit by block, sampled and photographed.","Close with the ask: inspection this week, and the settlement basis you're requesting."],"focus":["precision","structure"],"placeholder":"I'm filing a hail claim on policy 88-4471 for the July 14 storm: roughly 60 acres of apples affected across four blocks. Sampled counts show 35-40 strikes per hundred fruit in the north blocks and 10-15 in the south, photographed and dated the morning after."},
    {"id":"together-agri-mid-09","level":"mid","profession":"agriculture","title":"The year-end opening","scenario":"The annual review with the owner and the accountant: forty minutes, a year of work, and an audience of two who want different things — the owner wants the story, the accountant wants the variances. Your opening 4 sentences have to give the verdict, serve both readers, and set up the one big decision on the agenda.","task":"Write the 4-sentence opening: the year's verdict, the number for the accountant, the story for the owner, and the decision ahead.","tips":["Verdict first: the year in one sentence, against budget.","One precise number for the accountant, one plain-language proof for the owner — same fact, two frames.","End the opening on the decision the meeting exists to make."],"focus":["structure","impact"],"placeholder":"The year closed 4% over budget on income and 2% under on costs — our best margin in five seasons. For the story behind it: the early wheat sale and the dry-year irrigation calls did most of the work."},
    {"id":"together-agri-mid-10","level":"mid","profession":"agriculture","title":"Storm coming: two messages","scenario":"A named storm arrives in 36 hours. The boat needs securing, the crew needs tomorrow's plan, and the owner — who is away — needs to know his asset and his people are handled. Two messages, ten minutes: the crew brief and the owner note, each in its own register.","task":"Write both: the 2-3 sentence crew instruction and the 2-sentence owner note.","tips":["The crew version is tasks, times, and names: haul-out at 8, double lines, who does what.","The owner version is assurance with facts: secured by when, crew stood down, next update after the storm passes.","Neither message borrows the other's tone — precision for the deck, confidence for the owner."],"focus":["audience","structure"],"placeholder":"Crew: haul-out starts 8 a.m., all electronics off the boat by noon, double spring lines fore and aft — Danny and Cole, you're on lines with me. Owner: Boat's out of the water and stripped by tomorrow noon, crew stood down until the all-clear."},
    {"id":"together-agri-mid-11","level":"mid","profession":"agriculture","title":"Own it, fix it, keep the buyer","scenario":"Last week's lettuce shipment to the restaurant group arrived wilted — a cooler failure on your truck that you've since traced and fixed. The account is worth $40K a season and the chef is deciding whether to trust you again. One email: own it fully, show the fix precisely, and rebuild the confidence without groveling.","task":"Write the 4-sentence email: ownership, the traced cause, the fix, and the make-good.","tips":["Own it in sentence one — no weather, no 'unfortunately.'","The cause and fix specific: compressor relay, replaced, plus the temperature logger now on every load.","The make-good concrete: that shipment credited, and the logger readout attached to her invoices from now on."],"focus":["clarity","impact"],"placeholder":"Last week's lettuce arrived wilted because our truck's cooler failed en route — that's on us, and it's been credited in full. We traced it to a compressor relay, replaced it, and every load now carries a temperature logger."},
    {"id":"together-agri-mid-12","level":"mid","profession":"agriculture","title":"The tractor one-pager","scenario":"You're proposing the $160K tractor replacement in a one-page memo the owner will read once and hand to his accountant. It needs everything at once: the ask up front, precise numbers, the strongest counterargument answered, and a clean decision request — no adjective doing a number's job.","task":"Write the 4-5 sentence core of the memo: ask, cost case, the answered objection, and the decision line.","tips":["The ask in line one, with the number and the timing.","The case in comparisons: current repair trajectory and downtime days against the new payment.","Answer 'why not another rebuild' before the accountant asks it, then end on the yes/no and its date."],"focus":["structure","precision"],"placeholder":"I'm recommending we replace the 7810 this winter: $160K, financed, delivery by March. The old tractor cost $19K in repairs and eleven down days this season, and both numbers have grown three years running."},
    {"id":"together-agri-mid-13","level":"mid","profession":"agriculture","title":"The handover note","scenario":"You're away for ten days — your first real break in three seasons — and the assistant manager is holding the farm. Your handover note has to be everything you've practiced in miniature: prioritized, precise, written for his knowledge level, and short enough that he actually uses it instead of calling you at the lake.","task":"Write the 5-sentence handover: the one rule, the two live issues, the decision he can make alone, and the one that waits for you.","tips":["Open with the governing rule: when in doubt on animal health or safety, spend the money.","Live issues with their specifics: the cow under treatment and the irrigation pump that's been surging.","Draw the decision line explicitly — what's his to call, what waits — so he's empowered, not paralyzed."],"focus":["structure","audience"],"placeholder":"One rule while I'm gone: on animal health or crew safety, spend the money and tell me after. Two live issues: cow 47 finishes her treatment Thursday, and the north pump has been surging — Dan knows the reset."},
    {"id":"together-agri-mid-14","level":"mid","profession":"agriculture","title":"Bird flu next door","scenario":"Avian influenza was confirmed twelve kilometres away this morning. Within the hour you need two messages: lockdown instructions the crew can execute immediately, and an owner note that says what's at stake and what's already done. Clear, precise, calm — all three at once, no rehearsal time.","task":"Write both: the 3-sentence crew instruction and the 2-sentence owner note.","tips":["Crew message is verbs: no visitors, disinfectant stations at both barn doors, wild-bird contact points closed by noon.","One line of why — the confirmation nearby — so instructions carry weight without panic.","Owner note leads with what's protected: protocols live as of this morning, flock clean, next update daily."],"focus":["clarity","structure"],"placeholder":"Crew: bird flu was confirmed 12 km away, so as of now — no visitors past the gate, boot-dip stations at both barn doors, and the pond fence closed off by noon. Owner: AI confirmed at the Hendricks place this morning; our biosecurity protocols went live within the hour and the flock is healthy."},
    {"id":"together-agri-mid-15","level":"mid","profession":"agriculture","title":"The lender letter","scenario":"The bank's annual review letter is due, and this year it has to carry news in both directions: yields beat budget, but the hail claim and the price slide mean net income landed 8% under plan. The loan officer reads a hundred of these — yours needs the verdict up front, the numbers precise, and the risk management on display.","task":"Write the 4-5 sentence letter core: the verdict, the numbers both directions, and the evidence you manage risk.","tips":["Verdict first, both barrels: production above plan, income below it, loan fully serviced.","Precise on the miss: 8% under plan, and exactly why — the hail gap and the September price.","Show the risk system, not just the season: insurance collected, forward sales that cushioned the slide, next year's coverage adjusted."],"focus":["structure","precision"],"placeholder":"The operation finished the year with production 6% over budget and net income 8% under plan — the gap is the hail deductible and the September price slide — with all loan obligations met on schedule."},
    {"id":"together-agri-mid-16","level":"mid","profession":"agriculture","title":"The chef's complaint, answered","scenario":"The restaurant's chef emailed that the last two deliveries of greens 'weren't up to your usual standard' — no specifics. You've checked: one delivery ran warm in Friday traffic, the other was fine as far as you can tell. The reply needs everything: taking it seriously, precise facts, honest uncertainty, and a fix.","task":"Write the 4-sentence reply: the thanks-and-seriousness, what you found on each delivery, and the fix and follow-up.","tips":["Open by taking it straight — a defensive first line loses the account.","Facts by delivery: Friday's ran 40 minutes over in traffic and likely warmed; Tuesday's checks out clean, and say you'd like specifics.","The fix concrete: earlier route slot and cold-chain logger, plus the invitation to flag anything within a day while it can be verified."],"focus":["clarity","impact"],"placeholder":"Thank you for flagging this — I take it seriously and I've traced both deliveries. Friday's ran 40 minutes over in traffic and I believe the greens warmed; Tuesday's I can't fault from my end, so specifics would help me find what you saw."},
    {"id":"together-agri-mid-17","level":"mid","profession":"agriculture","title":"Day one, done right","scenario":"Six new seasonal workers start Monday. Your day-one talk sets everything: safety, standards, who's who, and pay. Most first-day briefings are forgettable fire hoses. Yours has to be structured to be remembered — three things, in their language, with names and numbers where it counts.","task":"Script the 4-5 sentence welcome: the frame, the three things, and the close that opens the door to questions.","tips":["Frame it as three things — safety, quality, pay — and keep every sentence inside them.","Their language: 'if a machine is running, the driver sees you first' beats any policy phrasing.","Close with names: your lead is Rosa, payday is Friday, and any question goes to either of us — no bad questions in week one."],"focus":["audience","clarity"]},
    {"id":"together-agri-mid-18","level":"mid","profession":"agriculture","title":"The AGM address","scenario":"You're addressing forty co-op members at the AGM: results, the dryer decision passed last spring, and the year ahead. Some members trust you, some voted against the dryer, all of them own the place. Open and close are what they'll remember — one governing message, evidence, and a finish with presence.","task":"Write the 3-sentence opening and the 2-sentence close of the address.","tips":["The opening carries the verdict and the year's one message: the co-op is stronger than it was a year ago, and here's the number that proves it.","Address the dryer skeptics with its first-season results — respect the no votes by showing them the arithmetic.","The close restates the message and points forward: same discipline, next project, their co-op."],"focus":["impact","audience"],"placeholder":"A year ago this room debated whether the dryer was worth the debt — this year it dried 180,000 bushels, cut our elevator queue to zero, and is running eight months ahead of its payback schedule."},
    {"id":"together-agri-mid-19","level":"mid","profession":"agriculture","title":"The drought playbook memo","scenario":"It's June 20, thirty days without rain, and the owner wants to know the plan if it continues. This memo is the full craft: structured by trigger dates, precise about numbers, honest about unknowns, and short enough to act on. Panic plans ramble; playbooks decide in advance.","task":"Write the 4-5 sentence memo: the frame, the three trigger points with their actions, and what's already in motion.","tips":["Frame first: three decision points, each with a date and an action — decided now, while heads are cool.","Each trigger one sentence: July 5 no rain, graze the hay regrowth; July 20, cull list executes; August 1, buy feed before the district bids it up.","Close with what's already moving, so the memo reads as a plan in motion rather than a forecast of pain."],"focus":["structure","precision"],"placeholder":"If the dry run continues, here's the playbook — three trigger dates, each with its action, decided now so we're not improvising in August. July 5 without rain: the herd moves onto hay regrowth and we stop cutting."},
    {"id":"together-agri-mid-20","level":"mid","profession":"agriculture","title":"The equipment-share agreement","scenario":"The neighbor said yes to sharing the corn header — now the terms email has to hold up next October when you both want the machine the same week. Plain language, precise terms, the conflict rule up front, and a tone that keeps a thirty-year neighborly relationship intact.","task":"Write the 4-5 sentence terms email: the deal, the costs split, the conflict rule, and the review date.","tips":["Restate the deal in one line — half the purchase, half the insurance, repairs split by hours used.","The conflict rule is the whole document: he gets first call on the four overlap days this year, you get them next year, alternating.","End warm and concrete: a beer in November to review how year one went."],"focus":["precision","clarity"],"placeholder":"Putting our handshake in writing: we split the header 50/50 — purchase, insurance, and repairs by hours logged. On the four days our harvests overlap, you get first call this year and I get it next, alternating after that."},
    {"id":"together-agri-mid-21","level":"mid","profession":"agriculture","title":"The expansion story for the paper","scenario":"The local paper is writing about your barn expansion and the reporter emailed five questions, including 'some residents worry about smell and truck traffic — your response?' Your written answers will be quoted verbatim. Everything applies: audience, precision, presence, and not a single defensive sentence.","task":"Write the 3-4 sentence answer to the neighbors-concern question, quotable and concrete.","tips":["Take the concern as legitimate in the first clause — dismissing neighbors in print costs years.","Concrete practices beat assurances: the covered manure storage, the truck route agreement, the open-barn day.","Give the accountability line: your phone number is on the farm gate, and you answer it."],"focus":["audience","impact"],"placeholder":"Those concerns are fair, and they shaped the design: the new barn includes covered manure storage that cuts odor substantially, and we've agreed on a truck route that keeps our haulers off the school road entirely."},
    {"id":"together-agri-mid-22","level":"mid","profession":"agriculture","title":"The end-of-season message","scenario":"The last bin is in and the seasonal crew scatters next week. Your end-of-season message does three jobs at once: real thanks with specifics, the rehire offer with dates, and the one piece of feedback that makes next year better. Generic gratitude does none of them.","task":"Write the 4-sentence message: the specific thanks, the season's number, the rehire offer, and the ask.","tips":["Thanks that proves you watched: the record packing week, the zero-injury season.","One number they own: 41,000 bins, the farm's best.","The rehire offer with a date and a deadline, then the ask: tell you by March 1, and bring a friend as good as they are."],"focus":["audience","impact"],"placeholder":"That's the last bin — 41,000 for the season, the best this farm has ever done, and the first harvest in years without a single injury. That was you."},
    {"id":"together-agri-mid-23","level":"mid","profession":"agriculture","title":"One incident, three readers","scenario":"A pallet stack toppled in the packing shed and broke a worker's foot. The incident report you write tonight goes three places: the insurer, the owner, and the safety file the inspector may someday read. One document, three audiences — which means facts that hold for all of them and speculation for none.","task":"Write the 4-sentence factual core that serves all three readers.","tips":["Facts only, timestamped: what was stacked, how high, who was where, when.","No speculation and no self-incrimination beyond fact — 'the stack exceeded the posted height' is a fact; 'we were careless' is a gift to nobody.","Corrective actions dated and specific: restacking standard, floor marking, toolbox talk held — that's the sentence every reader needs."],"focus":["audience","structure"],"placeholder":"At 2:40 p.m. Tuesday, a pallet stack in bay 3 — stacked five high against a posted limit of four — toppled while J. Alvarez was passing, fracturing his left foot. First aid was immediate, he was driven to the clinic within twenty minutes, and the incident was logged the same hour."},
    {"id":"together-agri-mid-24","level":"mid","profession":"agriculture","title":"Five minutes, three decisions","scenario":"The owner is boarding a flight and gives you five minutes by phone. You need three decisions: the fungicide pass (yes/no by tomorrow), the hay buyer's offer (accept or counter), and the part-time mechanic hire. Five minutes, three decisions, zero storytelling — the agenda is the skill.","task":"Script the 4-5 sentence call: the frame, then each decision with its recommendation and deadline.","tips":["Frame in ten seconds: three decisions, I'll give you my recommendation on each.","Each one is a sentence: the decision, your pick, the number that justifies it, the deadline.","Take yeses as you go — don't save all three for the end and lose the call to boarding."],"focus":["structure","concision"],"placeholder":"Three decisions before you board, and I have a recommendation on each. One: fungicide on the wheat — I say yes, scouting hit threshold, $18 an acre, and I need the answer by tonight."},
    {"id":"together-agri-mid-25","level":"mid","profession":"agriculture","title":"Edit your own spring plan","scenario":"Your spring workplan memo to the owner is drafted: 900 words, opens with a paragraph about the winter, buries the two decisions he must make, hedges every recommendation, and says 'utilize' four times. Before sending, run it against everything — lead, audience, structure, concision, precision, presence.","task":"Write the 3-sentence replacement opening that would survive the full rubric.","tips":["Lead with the decisions: two things need his yes by March 1 — name them with their numbers.","Cut the winter recap entirely; he lived through the same winter.","Read it as him, on a phone, in a truck: if sentence one doesn't earn sentence two, cut deeper."],"focus":["concision","structure"],"placeholder":"Two decisions need your yes by March 1: the seed order ($64K, locked pricing ends that day) and the second planter operator hire. Everything else in this plan is informational — the field sequence, the fertilizer program, and the machinery schedule are set."}
  ],
};
